INSERT INTO `news` (`id`, `id_cat`, `status`, `title`, `introduce`, `content`, `image`, `views`, `created_at`, `updated_at`, `created_by`) VALUES
(1, 2, 1, 'Mua online đi - Ngại gì Cô Vy', '', 'Những ý tưởng dưới đây sẽ giúp bạn sắp xếp tủ quần áo trong phòng ngủ chật hẹp của mình một cách dễ dàng và hiệu quả nhất. ', 'news1.jpg', 1546, '2020-04-25 11:49:16', '2020-04-25 12:24:15', 'Administrator'),
(2, 2, 0, '\"Ưu đãi giá đẹp - Làm việc tại nhà\" cùng LG Việt Nam từ 1/4 - 30/4', '', 'Chúng tôi sẽ tư vấn cải tạo và bố trí nội thất để giúp phòng ngủ của chàng trai độc thân thật thoải mái, thoáng mát và sáng sủa nhất. ', 'news2.jpg', 568, '2020-04-25 11:49:23', '2020-04-25 12:05:22', 'Super User'),
(3, 2, 1, 'MUA ONLINE ĐI - NGẠI GÌ \"CÔ VY\"', '', 'Đồ gỗ nội thất ngày càng được sử dụng phổ biến nhờ vào hiệu quả mà nó mang lại cho không gian kiến trúc. Xu thế của các gia đình hiện nay là muốn đem thiên nhiên vào nhà ', 'news3.jpg', 786, '2020-04-25 11:49:28', '2020-04-25 12:56:32', 'Administrator'),
(16, 1, 1, 'Tăng tốc kết nối mạng khi làm việc tại nhà với APKCombo VPN', NULL, '<p><img alt=\"Tăng tốc kết nối mạng khi làm việc tại nhà với APKCombo VPN\" src=\"https://genk.mediacdn.vn/thumb_w/640/139269124445442048/2020/4/7/photo1586229486640-1586229487278358841188.png\" style=\"width:640px\" title=\"Tăng tốc kết nối mạng khi làm việc tại nhà với APKCombo VPN\" /></p>\r\n\r\n<h2><span style=\"font-size:12px\">Giải ph&aacute;p tăng tốc duyệt web cho smartphone giờ đ&atilde; c&oacute; thể sử dụng tr&ecirc;n m&aacute;y t&iacute;nh Windows 10.<br />\r\nMặc d&ugrave; Google cũng c&oacute; một dịch vụ DNS c&ocirc;ng cộng của ri&ecirc;ng m&igrave;nh, nhưng Cloudflare cho tốc độ nhanh hơn, khiến c&aacute;c kết nối của bạn cảm thấy &quot;tức th&igrave;&quot; hơn. Do đ&oacute;, x&eacute;t về mặt n&agrave;o đ&oacute; th&igrave; WARP đang dần được sử dụng nhiều hơn so với Google DNS. Th&ecirc;m v&agrave;o đ&oacute;, Cloudflare c&ograve;n quảng c&aacute;o dịch vụ n&agrave;y hỗ trợ c&aacute;c t&iacute;nh năng bảo mật như DNS-over-TLS v&agrave; DNS-over-HTTPS, với c&aacute;c ch&iacute;nh s&aacute;ch nghi&ecirc;m ngặt như kh&ocirc;ng ghi nhật k&yacute;, x&oacute;a to&agrave;n bộ lưu trữ sau 24 giờ&hellip;</span></h2>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Tăng tốc kết nối mạng khi làm việc tại nhà với APKCombo VPN - Ảnh 1.\" id=\"img_171820617897848832\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/7/1-15862292258811822099538.png\" title=\"Tăng tốc kết nối mạng khi làm việc tại nhà với APKCombo VPN - Ảnh 1.\" /></p>\r\n\r\n<p><span style=\"font-size:14px\">Cloudflare n&oacute;i h&atilde;ng x&acirc;y dựng WARP xung quanh giao thức dựa tr&ecirc;n UDP được tối ưu h&oacute;a cho Internet di động. WARP cũng tận dụng mạng lưới to&agrave;n cầu khổng lồ của Cloudflare, cho ph&eacute;p kết nối với c&aacute;c m&aacute;y chủ trong v&ograve;ng một phần ngh&igrave;n gi&acirc;y cho hầu hết người d&ugrave;ng Internet tr&ecirc;n thế giới. C&aacute;c thử nghiệm từ h&atilde;ng cho thấy Warp sẽ tăng đ&aacute;ng kể hiệu suất kết nối Internet.</span></p>\r\n\r\n<p><span style=\"font-size:14px\">Hiện tại WARP được đưa v&agrave;o ứng dụng 1.1.1.1 v&agrave; được ph&aacute;t h&agrave;nh miễn ph&iacute; cho 02 nền tảng di động l&agrave; iOS v&agrave; Android. Phi&ecirc;n bản d&agrave;nh cho macOS v&agrave; Windows vẫn đang được ph&aacute;t triển. Mặc d&ugrave; vậy, người d&ugrave;ng Windows v&agrave; macOS c&oacute; thể sử dụng WARP+ của Cloudflare th&ocirc;ng qua ứng dụng APKCombo VPN được c&aacute;c th&agrave;nh vi&ecirc;n của cộng đồng J2 Team (Việt Nam) ph&aacute;t triển. Cụ thể như sau.</span></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Tăng tốc kết nối mạng khi làm việc tại nhà với APKCombo VPN - Ảnh 2.\" id=\"img_171820617705365504\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/7/2-1586229226139976183893.png\" title=\"Tăng tốc kết nối mạng khi làm việc tại nhà với APKCombo VPN - Ảnh 2.\" /></p>\r\n\r\n<p><strong>Bước 1: Truy cập v&agrave;o địa chỉ n&agrave;y v&agrave; tải về g&oacute;i c&agrave;i đặt APKCombo VPN ph&ugrave; hợp với cấu h&igrave;nh Windows của bạn.</strong></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Tăng tốc kết nối mạng khi làm việc tại nhà với APKCombo VPN - Ảnh 3.\" id=\"img_171820618175127552\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/7/3-1586229226426213469793.png\" title=\"Tăng tốc kết nối mạng khi làm việc tại nhà với APKCombo VPN - Ảnh 3.\" /></p>\r\n\r\n<p><strong>Bước 2: Khởi động v&agrave; c&agrave;i đặt APKCombo VPN. Qu&aacute; tr&igrave;nh c&agrave;i đặt diễn ra ho&agrave;n to&agrave;n tự động. Khi ho&agrave;n tất, bảng giao diện của APKCombo VPN sẽ hiện ra, bạn h&atilde;y nhấp v&agrave;o &quot;Active CloudFlare WARP+ VPN&quot;.</strong></p>\r\n\r\n<p><iframe height=\"0\" id=\"ads-place-2013326\" scrolling=\"no\" src=\"javascript:if(typeof(admSspPageRg)!=\'undefined\'){admSspPageRg.draw(2013326);}else{parent.admSspPageRg.draw(2013326);}\" width=\"0\"></iframe></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Tăng tốc kết nối mạng khi làm việc tại nhà với APKCombo VPN - Ảnh 4.\" id=\"img_171820618808463360\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/7/4-15862292267301455381372.png\" title=\"Tăng tốc kết nối mạng khi làm việc tại nhà với APKCombo VPN - Ảnh 4.\" /></p>\r\n\r\n<p><strong>Bước 3: Tiếp tục nhấn v&agrave;o &quot;Activate&quot;.</strong></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Tăng tốc kết nối mạng khi làm việc tại nhà với APKCombo VPN - Ảnh 5.\" id=\"img_171820619569635328\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/7/5-1586229226852378732299.png\" title=\"Tăng tốc kết nối mạng khi làm việc tại nhà với APKCombo VPN - Ảnh 5.\" /></p>\r\n\r\n<p>Qu&aacute; tr&igrave;nh kết nối v&agrave; k&iacute;ch hoạt c&aacute;c dữ liệu WARP+ sẽ bắt đầu.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Tăng tốc kết nối mạng khi làm việc tại nhà với APKCombo VPN - Ảnh 6.\" id=\"img_171820622283350016\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/7/6-158622922713539244172.png\" title=\"Tăng tốc kết nối mạng khi làm việc tại nhà với APKCombo VPN - Ảnh 6.\" /></p>\r\n\r\n<p>Khi ho&agrave;n tất, th&ocirc;ng b&aacute;o sẽ xuất hiện.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Tăng tốc kết nối mạng khi làm việc tại nhà với APKCombo VPN - Ảnh 7.\" id=\"img_171820622331682816\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/7/7-15862292273351728510074.png\" title=\"Tăng tốc kết nối mạng khi làm việc tại nhà với APKCombo VPN - Ảnh 7.\" /></p>\r\n\r\n<p>Qu&aacute; tr&igrave;nh sử dụng WARP+ sẽ được hiển thị rất r&otilde; ở khu vực Peer, qua đ&oacute; c&ograve;n cung cấp cho bạn c&aacute;c th&ocirc;ng số dữ liệu đ&atilde; sử dụng để bạn nắm r&otilde;.</p>', 'ttcn1.png', 0, '2020-04-28 15:20:20', '2020-04-28 15:20:20', 'Nguyễn Quí Hổ'),
(15, 2, 1, 'NHẬN TAI NGHE SENNHEISER KHI MUA MÀN HÌNH ASUS', NULL, '<p><span style=\"font-size:20px\"><strong>NHẬN TAI NGHE SENNHEISER KHI MUA M&Agrave;N H&Igrave;NH ASUS</strong></span><br />\r\n&nbsp;TechFast &nbsp;Tin khuyến m&atilde;i &nbsp;05/02/2020</p>\r\n\r\n<p><img src=\"https://file.hstatic.net/1000233206/file/2616383e37ebcfb596fa_8afdda2db0bf4e1c87ba4773a8ccb54b_1024x1024.jpg\" /></p>\r\n\r\n<p><br />\r\n<strong>CHƯƠNG TR&Igrave;NH KHUYẾN M&Atilde;I</strong>: d&agrave;nh cho kh&aacute;ch h&agrave;ng mua bất cứ sản phẩm m&agrave;n h&igrave;nh ASUS VA24EHE/VA27EHE v&agrave; VL249HE/VL279HE Series sẽ nhận ngay 1 tai nghe Sennheiser trị gi&aacute; 690,000 VNĐ</p>\r\n\r\n<p>.<strong> H&igrave;nh thức nhận qu&agrave;</strong>: scan QR code trong ảnh để đăng k&iacute; th&ocirc;ng tin v&agrave;o link đăng k&iacute; nhận qu&agrave; của ASUS. ASUS sẽ chuyển đến tận nh&agrave; kh&aacute;ch h&agrave;ng.</p>\r\n\r\n<p>. <strong>Thời gian</strong>: bắt đầu từ 5/5 cho đến khi hết qu&agrave; tặng.</p>', 'ttkm5.jpg', 0, '2020-04-28 15:16:09', '2020-04-28 15:16:09', 'Nguyễn Quí Hổ'),
(11, 2, 1, 'MỪNG ĐẠI LỄ - ACER SALE SIÊU KHỦNG 30.4 & 1.5.2020', NULL, '<p><strong>MỪNG ĐẠI LỄ - ACER SALE SI&Ecirc;U KHỦNG 30.4 &amp; 1.5.2020</strong></p>\r\n\r\n<p><img src=\"https://file.hstatic.net/1000233206/file/mung-le-sale-khung-acer_ab4e04b0225b4d1994c74d5fcb7c267c_1024x1024.png\" /></p>\r\n\r\n<p>Ch&agrave;o mừng ng&agrave;y Giải ph&oacute;ng miền Nam 30-4 v&agrave; Quốc tế lao động 1-5, Nhằm hỗ trợ kh&aacute;ch h&agrave;ng v&agrave; k&iacute;ch cầu mua sắm trong đợt nghỉ lễ d&agrave;i ng&agrave;y, ACER đồng h&agrave;nh c&ugrave;ng TechFast triển khai chương tr&igrave;nh khuyến m&atilde;i giảm gi&aacute; cực sốc v&agrave; tặng qu&agrave; cực khủng &aacute;p dụng cho kh&aacute;ch h&agrave;ng khi mua Laptop Acer.</p>\r\n\r\n<p>Nội dung chương tr&igrave;nh:<br />\r\nLaptop Acer gi&aacute; cực sốc giảm đến 30%<br />\r\nNhận bộ qu&agrave; tặng trị gi&aacute; đến 8 triệu đồng.</p>\r\n\r\n<p><br />\r\nThời gian diễn ra: Từ ng&agrave;y 2-4 -&gt; 3-5-2020</p>\r\n\r\n<p>C&aacute;c ưu đ&atilde;i khi mua sắm tại TechFast:<br />\r\n- Giao h&agrave;ng nhanh trong 2 giờ<br />\r\n- Free shipping to&agrave;n quốc.<br />\r\n- Trả g&oacute;p l&atilde;i suất 0%.</p>', 'ttkm1.jpg', 0, '2020-04-28 15:02:00', '2020-04-28 15:02:00', 'Nguyễn Quí Hổ'),
(12, 2, 1, 'MUA KÈM CÙNG LAPTOP ASUS - NHẬN NGAY VOUCHER HẤP DẪN', NULL, '<p>MUA K&Egrave;M C&Ugrave;NG LAPTOP ASUS - NHẬN NGAY VOUCHER HẤP DẪN<br />\r\n&nbsp;TechFast &nbsp;Tin khuyến m&atilde;i &nbsp;25/04/2020</p>\r\n\r\n<p><img src=\"https://file.hstatic.net/1000233206/file/banner_adasd_75c6d6879f1c4d0c8f10e9b5b9219abf_1024x1024.jpg\" /></p>\r\n\r\n<p><br />\r\nNội Dung chương tr&igrave;nh:</p>\r\n\r\n<p>Kh&aacute;ch h&agrave;ng khi mua Laptop ASUS được giảm ngay 150,000đ khi mua k&egrave;m th&ecirc;m M&agrave;n h&igrave;nh hoặc Thiết bị mạng c&oacute; gi&aacute; b&aacute;n lẻ từ 2,990,000đ trở l&ecirc;n v&agrave; Gaming Gear ASUS gi&aacute; b&aacute;n lẻ từ 990,000đ trở l&ecirc;n.</p>\r\n\r\n<p>Thời Gian chương tr&igrave;nh: 28.04 - 31.05.2020</p>\r\n\r\n<p>Sản phẩm tham khảo:&nbsp;</p>\r\n\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;- M&agrave;n h&igrave;nh ASUS -&gt; Tại đ&acirc;y</p>\r\n\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;- Router ASUS -&gt; Tại đ&acirc;y</p>\r\n\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;- Gaming Gear ASUS -&gt; Tại đ&acirc;y</p>\r\n\r\n<p>Lưu &yacute;:</p>\r\n\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;* Một Voucher chỉ &aacute;p dụng cho 1 sản phẩm mua k&egrave;m/Laptop.</p>\r\n\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;* Số lượng Voucher c&oacute; hạn.</p>', 'ttkm2.jpg', 0, '2020-04-28 15:05:36', '2020-04-28 15:05:36', 'Nguyễn Quí Hổ'),
(13, 2, 1, 'ACER PREDATOR HELIOS 300: \'MUA NGAY HÔM NAY, GIẢM NGAY 3 TRIỆU\'', NULL, '<p>ACER PREDATOR HELIOS 300: &#39;MUA NGAY H&Ocirc;M NAY, GIẢM NGAY 3 TRIỆU&#39;<br />\r\n&nbsp;TechFast &nbsp;Tin khuyến m&atilde;i &nbsp;11/04/2020<br />\r\nACER PREDATOR HELIOS 300<br />\r\nMUA NGAY H&Ocirc;M NAY, GIẢM NGAY 3 TRIỆU</p>\r\n\r\n<p><img src=\"https://file.hstatic.net/1000233206/file/voucher-helios-300__1__f48425a53d4a4b3d8f9e5d36f30623e1.jpg\" /></p>\r\n\r\n<p><br />\r\nT&ecirc;n chương tr&igrave;nh: &ldquo;MUA NGAY H&Ocirc;M NAY, GIẢM NGAY 3 TRIỆU&rdquo;</p>\r\n\r\n<p>Thời gian chương tr&igrave;nh: 10.04 đến 01.05.2020</p>\r\n\r\n<p>Qu&agrave; tặng: Giảm gi&aacute; 3.000.000VNĐ khi mua laptop gaming cao cấp Acer Predator Helios 300</p>', 'ttkm3.jpg', 0, '2020-04-28 15:08:34', '2020-04-28 15:08:34', 'Nguyễn Quí Hổ'),
(14, 2, 1, '[Samsung] Chương trình khuyến mãi #WORKFROMHOME', NULL, '<p><span style=\"font-size:20px\"><strong>[Samsung] Chương tr&igrave;nh khuyến m&atilde;i #WORKFROMHOME</strong></span><br />\r\n&nbsp;TechFast &nbsp;Tin khuyến m&atilde;i &nbsp;04/04/2020<br />\r\nTechFast đồng h&agrave;nh c&ugrave;ng Samsung trong thời gian chống dịch Covid 19 triển khai chương tr&igrave;nh khuyến m&atilde;i như sau:</p>\r\n\r\n<p>Hỗ trợ kh&aacute;ch h&agrave;ng đến 200,000 để n&acirc;ng cấp g&oacute;i internet tại nh&agrave;, phục vụ cho việc l&agrave;m việc tại nh&agrave; (WORK FROM HOME) hiệu quả hơn trong thời gian chống dịch Covid 19.</p>\r\n\r\n<p><img src=\"https://file.hstatic.net/1000233206/file/banner_fa__7c8730fd85884d6fa49abb9979bdb68d_1024x1024.jpg\" /></p>\r\n\r\n<p><strong>1. Thời gian chương tr&igrave;nh</strong>: 15.04.2020 - 30.04.2020</p>\r\n\r\n<p><strong>2. Nội dung chương tr&igrave;nh:</strong></p>\r\n\r\n<p>Kh&aacute;ch h&agrave;ng khi đặt mua m&agrave;n h&igrave;nh LCD Samsung 24inch sẽ được giảm ngay 100,000đ, 27inch sẽ được giảm ngay 200,000đ</p>\r\n\r\n<p>*Số lượng sản phẩm được &aacute;p dụng c&oacute; hạn</p>\r\n\r\n<p><strong>3. Sản phẩm &aacute;p dụng:</strong>&nbsp;</p>\r\n\r\n<p>M&agrave;n h&igrave;nh Samsung 24&quot; v&agrave; 27&quot;</p>', 'ttkm4.jpg', 0, '2020-04-28 15:10:56', '2020-04-28 15:10:56', 'Nguyễn Quí Hổ'),
(17, 1, 1, 'Quá đông người sử dụng Internet ở nhà? Đây là những cách để Wi-Fi nhà bạn khó bị sập hơn trong 15 ngày tới', NULL, '<p><img alt=\"Quá đông người sử dụng Internet ở nhà? Đây là những cách để Wi-Fi nhà bạn khó bị sập hơn trong 15 ngày tới\" src=\"https://genk.mediacdn.vn/thumb_w/640/139269124445442048/2020/4/2/photo1585809480409-1585809480781953704114.jpg\" style=\"width:640px\" title=\"Quá đông người sử dụng Internet ở nhà? Đây là những cách để Wi-Fi nhà bạn khó bị sập hơn trong 15 ngày tới\" /></p>\r\n\r\n<h2>Để ai cũng c&oacute; thế l&agrave;m việc hay Online bằng Wi-Fi một c&aacute;ch trơn tru nhất.</h2>\r\n\r\n<p>Trước t&igrave;nh h&igrave;nh dịch bệnh Covid-19 c&oacute; nhiều diễn biến phức tạp, l&agrave;m việc tại nh&agrave; được coi l&agrave; giải ph&aacute;p tối ưu cho nhiều người. Tuy nhi&ecirc;n, việc nghẽn mạng sẽ khiến cho người d&ugrave;ng kh&oacute; gửi tin nhắn, email hoặc l&agrave;m mất kết nối với c&aacute;c ứng dụng giao tiếp trực tuyến.&nbsp;</p>\r\n\r\n<p>Đặc biệt l&agrave; khi ở nh&agrave; c&oacute; nhiều người hơn b&igrave;nh thường, việc chập chờn với mạng internet cũng xảy ra thường xuy&ecirc;n hơn.</p>\r\n\r\n<p>Để giải quyết vấn đề nghẽn mạng v&agrave; tối ưu Wi-Fi trong m&ugrave;a dịch để đ&aacute;p ứng cả nh&agrave; d&ugrave;ng c&ugrave;ng l&uacute;c, b&agrave;i viết n&agrave;y sẽ cung cấp cho bạn một số gợi &yacute; như sau.</p>\r\n\r\n<p>1. Sử dụng nhiều bộ router ph&aacute;t Wi-Fi tr&ecirc;n c&ugrave;ng một mạng</p>\r\n\r\n<p>Đầu ti&ecirc;n, bạn n&ecirc;n nghĩ đến việc sử dụng th&ecirc;m nhiều router Wi-Fi/Accesspoint nhằm mở rộng v&ugrave;ng ph&aacute;t Wi-Fi, qua đ&oacute; dễ d&agrave;ng gi&uacute;p tăng số lượng người sử dụng ở kh&ocirc;ng gian rộng. Từ đ&oacute; c&oacute; thể khắc phục được c&aacute;c vấn đề về &quot;nghẽn mạng&quot; hay lỗi kh&ocirc;ng v&agrave;o mạng được do 1 bộ ph&aacute;t Wi-Fi kh&ocirc;ng đủ tải qu&aacute; nhiều thiết bị c&ugrave;ng l&uacute;c.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Quá đông người sử dụng Internet ở nhà? Đây là những cách để Wi-Fi nhà bạn khó bị sập hơn trong 15 ngày tới - Ảnh 1.\" id=\"img_170067260851884032\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/2/912520202729761870812685006596145191845888n-15858111911611475045076.jpg\" title=\"Quá đông người sử dụng Internet ở nhà? Đây là những cách để Wi-Fi nhà bạn khó bị sập hơn trong 15 ngày tới - Ảnh 1.\" /></p>\r\n\r\n<p>Việc lắp đặt từ 02 thiết bị router trở l&ecirc;n thường được c&aacute;c gia đ&igrave;nh sử dụng trong c&aacute;c thiết kế nh&agrave; c&oacute; c&aacute;c tầng (đối với nh&agrave; ống), c&aacute;c cửa h&agrave;ng ăn uống.</p>\r\n\r\n<p>Lấy v&iacute; dụ nếu nh&agrave; bạn c&oacute; 04 tầng th&igrave; bạn n&ecirc;n c&oacute; 4 thiết bị mạng, bao gồm một Modem Wi-Fi (ở tầng 1) v&agrave; 3 Router Wi-Fi (ở 3 tầng). C&aacute;ch thiết lập cũng kh&aacute; đơn giản như sau:</p>\r\n\r\n<p>- Bước 1:&nbsp;Sử dụng c&aacute;p để kết nối cổng LAN của Modem với cổng WAN của Router &quot;Tầng 2&quot;, sau đ&oacute; thiết lập IP của Router &quot;Tầng 2&quot; l&agrave; &quot;192.168.2.1&quot; v&agrave; chế độ DHCP của Router &quot;Tầng 2&quot; n&agrave;y phải được bật.</p>\r\n\r\n<p>- Bước 2:&nbsp;Sử dụng c&aacute;p để kết nối cổng LAN của Router &quot;Tầng 2&quot; với cổng WAN của Router &quot;Tầng 3&quot;, sau đ&oacute; thiết lập IP của Router &quot;Tầng 3&quot; l&agrave; &quot;192.168.3.1&quot; v&agrave; chế độ DHCP của Router &quot;Tầng 3&quot; n&agrave;y cũng phải được bật.</p>\r\n\r\n<p>- Bước 3:&nbsp;Cuối c&ugrave;ng, bạn sử dụng c&aacute;p để kết nối cổng LAN của Router &quot;Tầng 3&quot; với cổng WAN của Router &quot;Tầng 4&quot;, sau đ&oacute; thiết lập IP của Router &quot;Tầng 4&quot; l&agrave; &quot;192.168.4.1&quot; v&agrave; chế độ DHCP của Router &quot;Tầng 4&quot; n&agrave;y tất nhi&ecirc;n cũng phải được bật.</p>\r\n\r\n<p>Tương tự, nếu nh&agrave; bạn c&oacute; nhiều tầng hơn nữa th&igrave; c&aacute;ch thiết lập cũng tương tự như tr&ecirc;n.</p>\r\n\r\n<p>Việc set cố định dải IP của từng Router kh&aacute; quan trọng bởi rất nhiều router sử dụng 1 gateway default giống nhau, chỉ cần 1 trong 3 router tr&ugrave;ng IP với Modem th&igrave; mạng sẽ dễ d&agrave;ng bị treo to&agrave;n bộ, do đ&oacute; việc set tay IP l&agrave; cần thiết.</p>\r\n\r\n<p>2. Điều chỉnh lại băng th&ocirc;ng mạng (QoS)</p>\r\n\r\n<p>Về cơ bản, QoS (Quality of Service) sẽ kh&ocirc;ng l&agrave;m cho kết nối Internet của bạn nhanh hơn v&agrave; cũng kh&ocirc;ng mở rộng tổng băng th&ocirc;ng m&agrave; chỉ l&agrave;m cho bạn cảm thấy một số dịch vụ v&agrave; ứng dụng nhất định nhanh hơn khi mạng bị tắc nghẽn. Đ&acirc;y l&agrave; một trong những t&iacute;nh năng tr&ecirc;n Router Wi-Fi m&agrave; bạn n&ecirc;n biết nhằm tăng chất lượng trải nghiệm tr&ecirc;n đường truyền internet của bạn.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Quá đông người sử dụng Internet ở nhà? Đây là những cách để Wi-Fi nhà bạn khó bị sập hơn trong 15 ngày tới - Ảnh 2.\" id=\"img_170067260675723264\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/2/916288115370445339039333877128056829116416n-1585811191154422437044.jpg\" title=\"Quá đông người sử dụng Internet ở nhà? Đây là những cách để Wi-Fi nhà bạn khó bị sập hơn trong 15 ngày tới - Ảnh 2.\" /></p>\r\n\r\n<p><iframe height=\"0\" id=\"ads-place-2013326\" scrolling=\"no\" src=\"javascript:if(typeof(admSspPageRg)!=\'undefined\'){admSspPageRg.draw(2013326);}else{parent.admSspPageRg.draw(2013326);}\" width=\"0\"></iframe></p>\r\n\r\n<p>Phần lớn cơ chế QoS được xử l&yacute; th&ocirc;ng qua Router. Điều n&agrave;y l&agrave; bởi v&igrave; QoS l&agrave; &quot;sợi d&acirc;y kết nối&quot; giữa thiết bị của bạn với mạng Internet, v&agrave; đ&acirc;y cũng l&agrave; &quot;vị tr&iacute;&quot; ho&agrave;n hảo để xem c&aacute;c dữ liệu đến v&agrave; sắp xếp dữ liệu đ&oacute; v&agrave;o c&aacute;c thiết bị kh&aacute;c nhau tr&ecirc;n mạng.</p>\r\n\r\n<p>Nhiều thiết bị v&agrave; Router hỗ trợ giao thức c&oacute; t&ecirc;n gọi Wifi Multimedia (WMM) tự động ph&acirc;n loại dữ liệu th&agrave;nh 4 loại: Voice, Video, Best Effort v&agrave; Background theo thứ tự ưu ti&ecirc;n giảm dần. Hầu hết Router đều được t&iacute;ch hợp sẵn QoS v&agrave; hiển thị ở vị tr&iacute; dễ nh&igrave;n thấy, tuy nhi&ecirc;n một số Router kh&aacute;c phức tạp hơn. Thường th&igrave; người d&ugrave;ng c&oacute; thể t&igrave;m thấy t&ugrave;y chọn QoS trong mục Advanced tr&ecirc;n cửa sổ t&ugrave;y chỉnh giao diện web của Router.</p>\r\n\r\n<p>B&ecirc;n cạnh QoS, 1 số router c&ograve;n c&oacute; t&iacute;nh năng Bandwidth Limit cho người d&ugrave;ng giới hạn băng th&ocirc;ng tối đa&nbsp;&nbsp;cho 1 cổng mạng cụ thể. Nếu Modem nh&agrave; mạng c&oacute; hỗ trợ t&iacute;nh năng n&agrave;y h&atilde;y bật n&oacute; l&ecirc;n v&agrave; giới hạn băng th&ocirc;ng cho mỗi cổng mạng để kh&ocirc;ng c&oacute; cổng n&agrave;o sử dụng hết băng th&ocirc;ng của cổng kh&aacute;c.</p>\r\n\r\n<p>V&iacute; dụ đường truyền Internet c&aacute;p quang nh&agrave; bạn c&oacute; tốc độ 60Mbps, v&agrave; c&oacute; 3 router trong nh&agrave;, h&atilde;y chia cho mỗi cổng được sử dụng tối đa 20Mbps. Như vậy giả dụ như ở tầng 1 c&oacute; người đang tải game th&igrave; ở tầng 3 ch&uacute;ng ta vẫn xem Netflix, Youtube b&igrave;nh thường.</p>\r\n\r\n<p>3. Cập nhật firmware cho Router</p>\r\n\r\n<p>Việc cập nhật firmware cho Router sẽ gi&uacute;p khắc phục c&aacute;c lỗi c&ograve;n tồn đọng, cải thiện hiệu suất v&agrave; tốc độ trong một số trường hợp. V&igrave; c&aacute;ch thức thực hiện tr&ecirc;n mỗi d&ograve;ng Router l&agrave; kh&aacute;c nhau, do đ&oacute; bạn c&oacute; thể tham khảo th&ecirc;m th&ocirc;ng tin tr&ecirc;n Google.</p>\r\n\r\n<p>4. Thay đổi vị tr&iacute; đặt Router</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Quá đông người sử dụng Internet ở nhà? Đây là những cách để Wi-Fi nhà bạn khó bị sập hơn trong 15 ngày tới - Ảnh 3.\" id=\"img_170067261770436608\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/2/913051022455855865817333057170507410440192n-15858111910651771965340.jpg\" title=\"Quá đông người sử dụng Internet ở nhà? Đây là những cách để Wi-Fi nhà bạn khó bị sập hơn trong 15 ngày tới - Ảnh 3.\" /></p>\r\n\r\n<p>Vị tr&iacute; để Router cũng sẽ ảnh hưởng &iacute;t nhiều đến mạng Wi-Fi nh&agrave; mạng. Bạn n&ecirc;n để Wi-Fi ở giữa nh&agrave; v&agrave; &iacute;t c&oacute; c&aacute;c vật cản, v&igrave; đ&acirc;y l&agrave; vị tr&iacute; tốt nhất để mọi vị tr&iacute; trong nh&agrave; bạn c&oacute; thể bắt được Wi-Fi một c&aacute;ch tốt nhất. Router cũng n&ecirc;n để xa c&aacute;c thiết bị điện tử tivi, tủ lạnh, c&aacute;c vật dụng kim loại sẽ g&acirc;y nhiễm s&oacute;ng Wi-Fi của bạn.</p>\r\n\r\n<p><strong>5. Thay đổi k&ecirc;nh (channel) ph&aacute;t Wi-Fi của Router</strong></p>\r\n\r\n<p>Thay đổi k&ecirc;nh Wi-Fi (channel) sẽ gi&uacute;p tr&aacute;nh hiện tượng nhiễu s&oacute;ng khi bạn ở khu vực d&acirc;n cư đ&ocirc;ng hoặc chung cư c&oacute; nhiều Router ph&aacute;t s&oacute;ng trong c&ugrave;ng một k&ecirc;nh. Để thay đổi k&ecirc;nh - channel Wi-Fi rất đơn giản. Bạn chỉ cần đăng nhập v&agrave;o Router với link đăng nhập, t&agrave;i khoản v&agrave; mật khẩu thường ghi ở phần th&ocirc;ng tin thiết bị tr&ecirc;n Router.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Quá đông người sử dụng Internet ở nhà? Đây là những cách để Wi-Fi nhà bạn khó bị sập hơn trong 15 ngày tới - Ảnh 4.\" id=\"img_170067599860699136\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/2/9129089825244998744342704830495249035952128n-15858112720411831360564.png\" title=\"Quá đông người sử dụng Internet ở nhà? Đây là những cách để Wi-Fi nhà bạn khó bị sập hơn trong 15 ngày tới - Ảnh 4.\" /></p>\r\n\r\n<p>Sau khi đ&atilde; đăng nhập v&agrave;o router bạn chọn Wireless (mạng kh&ocirc;ng d&acirc;y) &gt; Wireless Settings (c&agrave;i đặt mạng kh&ocirc;ng d&acirc;y) &gt; Channel (k&ecirc;nh). Th&ocirc;ng thường c&aacute;c thiết bị ph&aacute;t Wi-Fi b&acirc;y của c&aacute;c nh&agrave; mạng theo chuẩn 2.4Ghz n&ecirc;n bạn n&ecirc;n chọn c&aacute;c k&ecirc;nh 1, 6, 11Ghz l&agrave; tốt nhất.</p>\r\n\r\n<p>6. N&acirc;ng cấp g&oacute;i cước Internet</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Quá đông người sử dụng Internet ở nhà? Đây là những cách để Wi-Fi nhà bạn khó bị sập hơn trong 15 ngày tới - Ảnh 5.\" id=\"img_170067599915225088\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/2/913470961512109762266324986841919855263744n-15858112720141513923981.jpg\" title=\"Quá đông người sử dụng Internet ở nhà? Đây là những cách để Wi-Fi nhà bạn khó bị sập hơn trong 15 ngày tới - Ảnh 5.\" /></p>\r\n\r\n<p>N&acirc;ng cấp tốc độ internet l&agrave; điều n&ecirc;n l&agrave;m khi m&agrave; nhu cầu sử dụng của gia đ&igrave;nh bạn tăng cao hơn trước do phải l&agrave;m việc v&agrave; học tập ở nh&agrave;. Những g&oacute;i cước cũ thật sự kh&ocirc;ng đủ để đ&aacute;p ứng, v&igrave; vậy, điều cần l&agrave;m l&agrave; n&ecirc;n n&acirc;ng cấp g&oacute;i cước internet để cho Wi-Fi nh&agrave; bạn trở n&ecirc;n mượt m&agrave; hơn, đ&aacute;p ứng được nhu cầu sử dụng hiện tại.</p>', 'ttcn2.jpg', 0, '2020-04-28 15:23:33', '2020-04-28 15:23:33', 'Nguyễn Quí Hổ'),
(18, 1, 1, 'Nếu lo ngại tính bảo mật khi sử dụng Zoom, hãy thử qua những giải pháp thay thế này', NULL, '<p><img alt=\"Nếu lo ngại tính bảo mật khi sử dụng Zoom, hãy thử qua những giải pháp thay thế này\" src=\"https://genk.mediacdn.vn/thumb_w/640/139269124445442048/2020/4/10/photo1586488369761-1586488370158154797159.jpg\" style=\"width:640px\" title=\"Nếu lo ngại tính bảo mật khi sử dụng Zoom, hãy thử qua những giải pháp thay thế này\" /></p>\r\n\r\n<h2>Zoom đang g&acirc;y kh&aacute; nhiều tranh c&atilde;i về t&iacute;nh ri&ecirc;ng tư, v&agrave; đ&acirc;y l&agrave; những lựa chọn an to&agrave;n thay thế.</h2>\r\n\r\n<p>Gần đ&acirc;y, kh&aacute; nhiều c&aacute;c th&ocirc;ng tin về t&iacute;nh ri&ecirc;ng tư khi sử dụng Zoom bị r&ograve; rỉ, v&agrave; động th&aacute;i lớn nhất cho việc n&agrave;y ch&iacute;nh l&agrave; Google cấm nh&acirc;n vi&ecirc;n sử dụng ứng dụng Zoom tr&ecirc;n m&aacute;y t&iacute;nh của c&ocirc;ng ty. K&egrave;m theo đ&oacute; l&agrave; c&aacute;c h&atilde;ng c&ocirc;ng nghệ lớn như Tesla hay cả ch&iacute;nh phủ Đ&agrave;i Loan cũng đ&atilde; ch&iacute;nh thức cấm sử dụng Zoom sau những l&ugrave;m x&ugrave;m về bảo mật của c&ocirc;ng cụ n&agrave;y.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Nếu lo ngại tính bảo mật khi sử dụng Zoom, hãy thử qua những giải pháp thay thế này - Ảnh 1.\" id=\"img_172906577511751680\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/10/1-1586488136917615212853.jpg\" title=\"Nếu lo ngại tính bảo mật khi sử dụng Zoom, hãy thử qua những giải pháp thay thế này - Ảnh 1.\" /></p>\r\n\r\n<p><em>Như vậy, nếu bạn l&agrave; một người kh&aacute; quan t&acirc;m về t&iacute;nh bảo mật th&igrave; việc bắt đầu sử dụng c&aacute;c lựa chọn họp v&agrave; l&agrave;m việc tại nh&agrave; thay thế Zoom l&agrave; điều n&ecirc;n l&agrave;m, sau đ&acirc;y sẽ l&agrave; một số gợi &yacute; m&agrave; bạn c&oacute; thể tham khảo.</em></p>\r\n\r\n<p><img alt=\"Nếu lo ngại tính bảo mật khi sử dụng Zoom, hãy thử qua những giải pháp thay thế này - Ảnh 2.\" id=\"img_172906573514575872\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/10/2-158648813712075900957.png\" title=\"Nếu lo ngại tính bảo mật khi sử dụng Zoom, hãy thử qua những giải pháp thay thế này - Ảnh 2.\" /></p>\r\n\r\n<p>L&agrave; t&iacute;nh năng được Microsoft bổ sung hồi đầu năm cho Skype. Skype Meet Now cho ph&eacute;p người d&ugrave;ng bắt đầu tr&ograve; chuyện video với người kh&aacute;c ngay lập tức, ngay cả khi người kia kh&ocirc;ng c&oacute; t&agrave;i khoản Skype. Skype sẽ tạo ra một li&ecirc;n kết mời m&agrave; bất cứ ai cũng c&oacute; thể truy cập để bắt đầu cuộc họp ngay lập tức. T&iacute;nh năng n&agrave;y c&oacute; sẵn cho cả thiết bị di động v&agrave; m&aacute;y t&iacute;nh để b&agrave;n.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Nếu lo ngại tính bảo mật khi sử dụng Zoom, hãy thử qua những giải pháp thay thế này - Ảnh 3.\" id=\"img_172906573638213632\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/10/3-1586488137188439808864.png\" title=\"Nếu lo ngại tính bảo mật khi sử dụng Zoom, hãy thử qua những giải pháp thay thế này - Ảnh 3.\" /></p>\r\n\r\n<p>H&atilde;y nghĩ n&oacute; giống như một cuộc gọi hội nghị video với Skype nhưng đi k&egrave;m li&ecirc;n kết tồn tại trong một khoảng thời gian. Người d&ugrave;ng chỉ cần tạo một li&ecirc;n kết v&agrave; chuyển n&oacute; đến những người cần tham dự cuộc họp. Khi họ nhấp v&agrave;o li&ecirc;n kết, họ sẽ được đưa tới Skype hoặc Web nếu thiết bị đ&oacute; c&oacute; ứng dụng Skype.</p>\r\n\r\n<p>Mặc d&ugrave; r&uacute;t gọn nhiều thao t&aacute;c nhưng Meet Now vẫn cung cấp một số t&iacute;nh năng thiết yếu của Skype. Cụ thể, người d&ugrave;ng c&oacute; thể ghi &acirc;m cuộc gọi để xem lại sau v&agrave; thậm ch&iacute; l&agrave;m mờ nền trước khi nhảy v&agrave;o cuộc hội nghị video để tr&aacute;nh những thứ ph&iacute;a sau lưng l&agrave;m ảnh hưởng đến trải nghiệm. Thậm ch&iacute; họ c&oacute; thể chia sẻ m&agrave;n h&igrave;nh v&agrave; hiển thị c&aacute;c b&agrave;i thuyết tr&igrave;nh hoặc slide.</p>\r\n\r\n<p><span style=\"color:#3498db\">Cisco Webex</span></p>\r\n\r\n<p>Cisco WebEx c&ograve;n c&oacute; thể hoạt đ&ocirc;̣ng tr&ecirc;n những đường truy&ecirc;̀n băng th&ocirc;ng hạn ch&ecirc;́ với hình ảnh video đ&ocirc;̣ nét cao, ti&ecirc;́t ki&ecirc;̣m chi phí, bảo m&acirc;̣t th&ocirc;ng tin chặt chẽ. Đ&acirc;y l&agrave; dịch vụ kh&aacute; lý tưởng trong vi&ecirc;̣c chia sẻ, trình di&ecirc;̃n tài li&ecirc;̣u hoặc xem trực ti&ecirc;́p màn hình của các thành vi&ecirc;n tham gia hoặc ghi lại toàn b&ocirc;̣ hình ảnh và n&ocirc;̣i dung cu&ocirc;̣c họp, các dữ li&ecirc;̣u trong cu&ocirc;̣c họp được ki&ecirc;̉m soát m&ocirc;̣t cách nghi&ecirc;m ngặt và an toàn.</p>\r\n\r\n<p><img alt=\"Nếu lo ngại tính bảo mật khi sử dụng Zoom, hãy thử qua những giải pháp thay thế này - Ảnh 4.\" id=\"img_172906573699129344\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/10/4-1586488137358335834496.png\" title=\"Nếu lo ngại tính bảo mật khi sử dụng Zoom, hãy thử qua những giải pháp thay thế này - Ảnh 4.\" /></p>\r\n\r\n<p>Cisco WebEx cũng cung c&acirc;́p hình ảnh trực tuy&ecirc;́n, chủ cu&ocirc;̣c họp có th&ecirc;̉ theo dõi màn hình người tham dự cu&ocirc;̣c họp, li&ecirc;̣t k&ecirc; các c&ocirc;ng vi&ecirc;̣c c&acirc;̀n thực hi&ecirc;̣n và ph&acirc;n vi&ecirc;̣c ngay tr&ecirc;n cu&ocirc;̣c họp trực tuy&ecirc;́n, ghi chép và lưu lại mọi tài li&ecirc;̣u chia sẻ qua lại trong bu&ocirc;̉i họp đ&ecirc;̉ theo dõi và hoàn thành. B&ecirc;n cạnh đó Cisco WebEx Meeting tích hợp tính năng nhắc nhở cu&ocirc;̣c họp th&ocirc;ng qua Microsoft Outlook Calendar.</p>\r\n\r\n<p><span style=\"color:#3498db\">StarLeaf</span></p>\r\n\r\n<p>Vốn được thiết kế cho c&aacute;c c&ocirc;ng ty quy m&ocirc; lớn, do đ&oacute; những người d&ugrave;ng c&aacute; nh&acirc;n sẽ &iacute;t c&oacute; cơ hội nghe thấy c&aacute;i t&ecirc;n Starleaf. Ch&iacute;nh v&igrave; thế, việc sử dụng Starleaf thường th&ocirc;ng qua hợp đồng hợp t&aacute;c, thay v&igrave; mua bản quyền cho một hay hai m&aacute;y t&iacute;nh đơn lẻ. Tuy nhi&ecirc;n, thời gian gần đ&acirc;y Starleaf đ&atilde; bắt đầu cung cấp phi&ecirc;n bản ứng dụng miễn ph&iacute; d&agrave;nh cho người d&ugrave;ng cơ bản, cho ph&eacute;p tiến h&agrave;nh c&aacute;c cuộc họp trực tuyến tối đa 20 người trong 46 ph&uacute;t.</p>\r\n\r\n<p><iframe height=\"0\" id=\"ads-place-2013326\" scrolling=\"no\" src=\"javascript:if(typeof(admSspPageRg)!=\'undefined\'){admSspPageRg.draw(2013326);}else{parent.admSspPageRg.draw(2013326);}\" width=\"0\"></iframe></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Nếu lo ngại tính bảo mật khi sử dụng Zoom, hãy thử qua những giải pháp thay thế này - Ảnh 5.\" id=\"img_172906583383773184\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/10/5-15864881384831740113655.png\" title=\"Nếu lo ngại tính bảo mật khi sử dụng Zoom, hãy thử qua những giải pháp thay thế này - Ảnh 5.\" /></p>\r\n\r\n<p>Ưu điểm của Starleaf ch&iacute;nh l&agrave; kh&ocirc;ng vướng quảng c&aacute;o, &iacute;t t&iacute;nh năng &quot;r&aacute;c&quot;, v&agrave; đặc biệt an to&agrave;n về kh&iacute;a cạnh bảo mật th&ocirc;ng tin.</p>\r\n\r\n<p><a href=\"https://jitsi.org/jitsi-meet/\" rel=\"nofollow\" target=\"_blank\" title=\"Jitsi Meet\"><strong>Jitsi Meet</strong></a></p>\r\n\r\n<p>Jitsi Meet cho ph&eacute;p người d&ugrave;ng khởi động cuộc họp nhanh chỉ bằng c&aacute;ch v&agrave;o trang web v&agrave; nhấn &quot;Go&quot;. Th&ecirc;m v&agrave;o đ&oacute;, nếu muốn tự ph&aacute;t triển phi&ecirc;n bản ứng dụng ri&ecirc;ng cho tổ chức v&agrave; doanh nghiệp, người d&ugrave;ng c&oacute; thể sử dụng Jitsi Videobridge. Đơn giản v&igrave; đ&acirc;y l&agrave; nền tảng sử dụng m&atilde; nguồn mở n&ecirc;n n&oacute; ho&agrave;n to&agrave;n miễn ph&iacute; đối với tất cả mọi người.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Nếu lo ngại tính bảo mật khi sử dụng Zoom, hãy thử qua những giải pháp thay thế này - Ảnh 6.\" id=\"img_172906578937810944\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/10/6-15864881385972078822370.png\" title=\"Nếu lo ngại tính bảo mật khi sử dụng Zoom, hãy thử qua những giải pháp thay thế này - Ảnh 6.\" /></p>\r\n\r\n<p>Mặc d&ugrave; miễn ph&iacute; v&agrave; l&agrave; nguồn mở nhưng việc sử dụng Jitsi Meet kh&aacute; bảo mật, th&ecirc;m v&agrave;o đ&oacute; n&oacute; kh&aacute; đơn giản để thao t&aacute;c, ngo&agrave;i ra bạn c&ograve;n c&oacute; thể ghi lại nội dung họp (chuyển thẳng v&agrave;o Dropbox) hay &quot;đ&aacute; bay&quot; những th&agrave;nh vi&ecirc;n họp g&acirc;y mất trật tự.</p>\r\n\r\n<p>Jitsi Meet hỗ trợ tối đa 75 người họp c&ugrave;ng l&uacute;c (35 người để c&oacute; chất lượng kết nối tối ưu), cho ph&eacute;p tiến h&agrave;nh họp nh&oacute;m ri&ecirc;ng khi cần, c&oacute; thể tương t&aacute;c với Slack, Google Calendar v&agrave; Office 365. Hiện nay, Jitsi Meet cũng đang thử nghiệm t&iacute;nh năng l&agrave;m mờ nền tương tự như Skype Meet Now.</p>\r\n\r\n<p><span style=\"color:#1abc9c\">Whereby</span></p>\r\n\r\n<p><img alt=\"Nếu lo ngại tính bảo mật khi sử dụng Zoom, hãy thử qua những giải pháp thay thế này - Ảnh 7.\" id=\"img_172906580585721856\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/10/7-15864881387721646099020.png\" title=\"Nếu lo ngại tính bảo mật khi sử dụng Zoom, hãy thử qua những giải pháp thay thế này - Ảnh 7.\" /></p>\r\n\r\n<p>Whereby kh&ocirc;ng ho&agrave;n to&agrave;n miễn ph&iacute; tất cả t&iacute;nh năng cho người d&ugrave;ng miễn ph&iacute;. Cụ thể, n&oacute; chỉ cho ph&eacute;p người d&ugrave;ng sử dụng ph&ograve;ng họp đơn với tối đa 4 người tham gia, nhưng c&oacute; k&egrave;m cơ chế &quot;kh&oacute;a cửa&quot; (buộc người muốn tham gia th&ecirc;m phải xin ph&eacute;p quản trị). Mỗi ph&ograve;ng họp sẽ c&oacute; đường dẫn ri&ecirc;ng để tham gia nhanh (tương tự Zoom).</p>', 'ttcn3.jpg', 0, '2020-04-28 15:27:16', '2020-04-28 15:27:16', 'Nguyễn Quí Hổ'),
(19, 1, 1, 'Họp trực tuyến nhưng máy tính không có webcam? Hãy tận dụng ngay chiếc smartphone của bạn', NULL, '<h1>Họp trực tuyến nhưng m&aacute;y t&iacute;nh kh&ocirc;ng c&oacute; webcam? H&atilde;y tận dụng ngay chiếc smartphone của bạn</h1>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Họp trực tuyến nhưng máy tính không có webcam? Hãy tận dụng ngay chiếc smartphone của bạn\" src=\"https://genk.mediacdn.vn/thumb_w/640/139269124445442048/2020/3/31/photo1585627510545-15856275108921845147645.jpg\" style=\"width:640px\" title=\"Họp trực tuyến nhưng máy tính không có webcam? Hãy tận dụng ngay chiếc smartphone của bạn\" /></p>\r\n\r\n<h2><span style=\"font-size:16px\">Nhiều khi chiếc &ldquo;webcam tự chế&rdquo; n&agrave;y của bạn c&ograve;n&hellip; xịn hơn webcam thực thụ</span>.<br />\r\n<span style=\"font-size:14px\">Họp hay học trực tuyến thời gian n&agrave;y l&agrave; điều hết sức b&igrave;nh thường. Tuy nhi&ecirc;n, nếu m&aacute;y t&iacute;nh của bạn kh&ocirc;ng c&oacute; trang bị webcam nhưng thời gian họp sắp đến th&igrave; việc l&ecirc; ch&acirc;n ra khỏi nh&agrave; l&uacute;c n&agrave;y c&oacute; thể l&agrave;m cho c&ocirc;ng việc của bạn bị gi&aacute;n đoạn. L&uacute;c n&agrave;y, chiếc smartphone th&acirc;n thương c&oacute; thể cứu bạn &quot;một b&agrave;n thua tr&ocirc;ng thấy&quot;.</span></h2>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Họp trực tuyến nhưng máy tính không có webcam? Hãy tận dụng ngay chiếc smartphone của bạn - Ảnh 1.\" id=\"img_169295973657350144\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/3/31/1-1585627301985573467754.jpg\" title=\"Họp trực tuyến nhưng máy tính không có webcam? Hãy tận dụng ngay chiếc smartphone của bạn - Ảnh 1.\" /></p>\r\n\r\n<p>Nh&igrave;n chung, với nguồn ứng dụng phong ph&uacute; như hiện nay th&igrave; kh&ocirc;ng kh&oacute; để bạn c&oacute; thể t&igrave;m thấy một lựa chọn biến chiếc smartphone của bạn th&agrave;nh webcam hay thậm ch&iacute; l&agrave; camera gi&aacute;m s&aacute;t. V&agrave; iVCam ch&iacute;nh l&agrave; gợi &yacute; d&agrave;nh cho bạn trong b&agrave;i viết n&agrave;y.</p>\r\n\r\n<p>iVCam&nbsp;được ph&aacute;t triển bởi e2eSoft, h&atilde;ng phần mềm kh&aacute; nổi tiếng với nhiều ứng dụng hữu &iacute;ch d&agrave;nh cho c&aacute;c nền tảng Windows, Android v&agrave; iOS. V&agrave; iVCam l&agrave; một ứng dụng c&oacute; chức năng cho ph&eacute;p người d&ugrave;ng chiếu h&igrave;nh ảnh trực tiếp từ camera smartphone l&ecirc;n m&agrave;n h&igrave;nh m&aacute;y t&iacute;nh với c&aacute;ch thiết lập đơn giản v&agrave; nhiều t&ugrave;y biến.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Họp trực tuyến nhưng máy tính không có webcam? Hãy tận dụng ngay chiếc smartphone của bạn - Ảnh 2.\" id=\"img_169295973892231168\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/3/31/2-1585627302121207746166.jpg\" title=\"Họp trực tuyến nhưng máy tính không có webcam? Hãy tận dụng ngay chiếc smartphone của bạn - Ảnh 2.\" /></p>\r\n\r\n<p>Để sử dụng, đầu ti&ecirc;n bạn cần phải thiết lập smartphone v&agrave; m&aacute;y t&iacute;nh sử dụng chung một mạng kết nối internet. Sau đ&oacute; truy cập v&agrave;o App Store, t&igrave;m v&agrave; c&agrave;i đặt ứng dụng iVCam.</p>', 'ttcn4.jpg', 0, '2020-04-28 15:29:24', '2020-04-28 15:29:24', 'Nguyễn Quí Hổ'),
(20, 1, 1, 'Những lưu ý về bảo mật khi làm việc với máy tính tại nhà mà bạn nên biết', NULL, '<h1>Những lưu &yacute; về bảo mật khi l&agrave;m việc với m&aacute;y t&iacute;nh tại nh&agrave; m&agrave; bạn n&ecirc;n biết</h1>\r\n\r\n<p><img alt=\"Những lưu ý về bảo mật khi làm việc với máy tính tại nhà mà bạn nên biết\" src=\"https://genk.mediacdn.vn/thumb_w/640/139269124445442048/2020/4/3/photo1585880141197-1585880141486306789952.jpg\" style=\"width:640px\" title=\"Những lưu ý về bảo mật khi làm việc với máy tính tại nhà mà bạn nên biết\" /></p>\r\n\r\n<h2><span style=\"font-size:14px\">V&agrave;i lưu &yacute; về bảo mật tr&ecirc;n m&aacute;y t&iacute;nh khi bạn l&agrave;m việc tại nh&agrave;.<br />\r\nNg&agrave;y c&agrave;ng nhiều c&ocirc;ng ty cho ph&eacute;p nh&acirc;n vi&ecirc;n l&agrave;m việc tại nh&agrave; để ngăn ngừa dịch virus corona chủng mới (SARS-CoV-2) l&acirc;y lan. Tuy nhi&ecirc;n, theo c&aacute;c chuy&ecirc;n gia về an ninh mạng th&igrave; khi l&agrave;m việc với m&aacute;y t&iacute;nh tại nh&agrave;, bạn rất dễ bị hacker tấn c&ocirc;ng hơn do kh&ocirc;ng được bảo vệ một c&aacute;ch đầy đủ.</span></h2>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Những lưu ý về bảo mật khi làm việc với máy tính tại nhà mà bạn nên biết - Ảnh 1.\" id=\"img_170356062807920640\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/3/photo-1-1585880047290245972590.jpg\" title=\"Những lưu ý về bảo mật khi làm việc với máy tính tại nhà mà bạn nên biết - Ảnh 1.\" /></p>\r\n\r\n<p>Đơn giản v&igrave; hiện tại &quot;virus corona&quot; hoặc &quot;Covid-19&quot; l&agrave; những cụm từ được sử dụng nhiều để đ&aacute;nh cắp th&ocirc;ng tin người d&ugrave;ng hoặc c&agrave;i những phần mềm độc hại v&agrave;o thiết bị c&aacute; nh&acirc;n. Những người bị hacker tấn c&ocirc;ng kh&ocirc;ng những đối mặt với rủi ro c&aacute; nh&acirc;n m&agrave; c&oacute; thể trở th&agrave;nh cửa hậu để tin tặc x&acirc;m nhập v&agrave;o hệ thống dữ liệu của tổ chức.</p>\r\n\r\n<p><em>Do đ&oacute;, để tr&aacute;nh việc bị tin tặc lợi dụng, cũng như tự tăng cường bảo mật m&aacute;y t&iacute;nh khi l&agrave;m việc tại nh&agrave;, bạn c&oacute; thể tham khảo một v&agrave;i gợi &yacute; sau đ&acirc;y.</em></p>\r\n\r\n<p><strong>1. Cập nhật c&aacute;c phần mềm c&agrave;i đặt tr&ecirc;n m&aacute;y t&iacute;nh l&ecirc;n phi&ecirc;n bản mới nhất</strong></p>\r\n\r\n<p>Đ&acirc;y l&agrave; việc l&agrave;m đầu ti&ecirc;n m&agrave; bạn n&ecirc;n lưu &yacute; v&agrave; thực hiện đầu ti&ecirc;n khi bắt đầu l&agrave;m việc với m&aacute;y t&iacute;nh tại nh&agrave;. Việc kiểm tra, c&agrave;i đặt c&aacute;c bản cập nhật mới cho phần mềm m&igrave;nh thường d&ugrave;ng được xem như l&agrave; một việc l&agrave;m cần thiết nhằm gi&uacute;p đảm bảo c&aacute;c phần mềm n&agrave;y lu&ocirc;n ở trạng th&aacute;i sử dụng tốt nhất.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Những lưu ý về bảo mật khi làm việc với máy tính tại nhà mà bạn nên biết - Ảnh 2.\" id=\"img_170356152712826880\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/3/2-158588006944650503027.png\" title=\"Những lưu ý về bảo mật khi làm việc với máy tính tại nhà mà bạn nên biết - Ảnh 2.\" /></p>\r\n\r\n<p>B&ecirc;n cạnh đ&oacute;, việc c&agrave;i đặt phi&ecirc;n bản mới c&ograve;n gi&uacute;p phần mềm khắc phục c&aacute;c lỗi ph&aacute;t sinh ở phi&ecirc;n bản cũ v&agrave; sử dụng th&ecirc;m được c&aacute;c t&iacute;nh năng mới m&agrave; nh&agrave; ph&aacute;t triển bổ sung th&ecirc;m.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Những lưu ý về bảo mật khi làm việc với máy tính tại nhà mà bạn nên biết - Ảnh 3.\" id=\"img_170356152905764864\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/3/3-1585880069724395439603.png\" title=\"Những lưu ý về bảo mật khi làm việc với máy tính tại nhà mà bạn nên biết - Ảnh 3.\" /></p>\r\n\r\n<p>Bạn c&oacute; thể truy cập v&agrave;o trang web của nh&agrave; ph&aacute;t triển để tải v&agrave; c&agrave;i đặt phi&ecirc;n bản mới cho phần mềm hoặc sử dụng c&ocirc;ng cụ&nbsp;Ucheck&nbsp;để thao t&aacute;c được nhanh hơn.</p>\r\n\r\n<p>2. K&iacute;ch hoạt t&iacute;nh năng x&aacute;c thực hai yếu tố</p>\r\n\r\n<p>X&aacute;c thực hai bước l&agrave; phương ph&aacute;p bảo mật cộng th&ecirc;m trước khi truy cập v&agrave;o t&agrave;i khoản. N&oacute; y&ecirc;u cầu bất kỳ ai đăng nhập v&agrave;o t&agrave;i khoản của bạn kh&ocirc;ng những phải c&oacute; mật khẩu m&agrave; c&ograve;n cần m&atilde; truy cập. M&atilde; n&agrave;y c&oacute; thể gửi đến t&agrave;i khoản email của bạn hoặc lấy trong ứng dụng Authentication tr&ecirc;n điện thoại.</p>\r\n\r\n<p>Tr&ecirc;n thực tế, 90% mật khẩu c&oacute; thể bị bẻ kh&oacute;a trong v&ograve;ng 6 giờ, 2 phần 3 người d&ugrave;ng internet sử dụng c&ugrave;ng mật khẩu ở mọi nơi. C&aacute;c đợt tấn c&ocirc;ng mạng chuy&ecirc;n nghiệp c&ograve;n c&oacute; thể kiểm thử h&agrave;ng tỉ mật khẩu trong v&ograve;ng v&agrave;i gi&acirc;y. Ch&iacute;nh v&igrave; điểm yếu n&agrave;y c&aacute;c nh&agrave; cung cấp dịch vụ tr&ecirc;n thế giới đ&atilde; cố gắng tạo th&ecirc;m một lớp x&aacute;c thực nữa để cải thiện t&igrave;nh trạng t&agrave;i khoản người d&ugrave;ng bị hacked.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Những lưu ý về bảo mật khi làm việc với máy tính tại nhà mà bạn nên biết - Ảnh 4.\" id=\"img_170356152960290816\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/3/4-1585880069743882463133.png\" title=\"Những lưu ý về bảo mật khi làm việc với máy tính tại nhà mà bạn nên biết - Ảnh 4.\" /></p>\r\n\r\n<p><iframe height=\"0\" id=\"ads-place-2013326\" scrolling=\"no\" src=\"javascript:if(typeof(admSspPageRg)!=\'undefined\'){admSspPageRg.draw(2013326);}else{parent.admSspPageRg.draw(2013326);}\" width=\"0\"></iframe></p>\r\n\r\n<p>Bước bảo mật cộng th&ecirc;m n&agrave;y khiến t&agrave;i khoản của bạn kh&oacute; bị x&acirc;m nhập hơn rất nhiều, cũng như việc n&oacute; c&oacute; khả năng ph&ograve;ng chống trường hợp bạn gặp m&atilde; độc c&oacute; khả năng đ&aacute;nh cắp th&ocirc;ng tin truy cập của bạn.</p>\r\n\r\n<p>3. Sử dụng tr&igrave;nh antivirus tin cậy</p>\r\n\r\n<p>Đ&atilde; kh&ocirc;ng hiếm những trường hợp người d&ugrave;ng m&aacute;y t&iacute;nh bị c&aacute;c t&iacute;n tặc đ&aacute;nh cắp dữ liệu v&agrave; ph&aacute; hủy hệ thống m&aacute;y t&iacute;nh. C&aacute;c tin tặc thực hiện h&agrave;nh vi tr&ecirc;n th&ocirc;ng qua virus, họ sử dụng nhiều thủ đoạn để c&oacute; thể lấy cắp th&ocirc;ng tin nhạy cảm v&agrave; bảo mật của bạn. Ch&iacute;nh v&igrave; thế, để bảo vệ m&aacute;y t&iacute;nh lu&ocirc;n được an to&agrave;n trước c&aacute;c cuộc tấn c&ocirc;ng của virus, c&aacute;ch tốt nhất l&agrave; bạn n&ecirc;n c&agrave;i đặt những phần mềm chống virus cho m&aacute;y t&iacute;nh của m&igrave;nh.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"Những lưu ý về bảo mật khi làm việc với máy tính tại nhà mà bạn nên biết - Ảnh 5.\" id=\"img_170356153128062976\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/3/5-1585880069877247132004.png\" title=\"Những lưu ý về bảo mật khi làm việc với máy tính tại nhà mà bạn nên biết - Ảnh 5.\" /></p>\r\n\r\n<p>Như ch&iacute;nh c&aacute;i t&ecirc;n của n&oacute; đ&atilde; cho thấy, phần mềm diệt virus sẽ t&igrave;m kiếm v&agrave; loại bỏ c&aacute;c virus đang ẩn n&aacute;u tr&ecirc;n m&aacute;y t&iacute;nh của bạn. Khi bạn đ&atilde; c&agrave;i đặt một chương tr&igrave;nh antivirus cho m&aacute;y t&iacute;nh th&igrave; kh&ocirc;ng cần qu&aacute; lo lắng bởi n&oacute; sẽ bảo vệ bạn khỏi bất kỳ loại virus n&agrave;o đang cố gắng x&acirc;m nhập v&agrave;o hệ thống. Trong đa số c&aacute;c trường hợp, phần mềm antivirus sẽ chủ động x&oacute;a bỏ virus khỏi hệ thống để ngăn chặn l&acirc;y lan.</p>\r\n\r\n<p>Mặc định Windows 10 đ&atilde; c&oacute; sẳn Windows Security, tuy nhi&ecirc;n nếu bạn muốn việc bảo mật được tối ưu hơn, h&atilde;y sử dụng c&aacute;c phần mềm bản quyền của c&aacute;c h&atilde;ng antivirus nổi tiếng như Kaspersky, Bitdefender,&hellip;</p>\r\n\r\n<p>4. Sử dụng VPN</p>\r\n\r\n<p>VPN l&agrave; mạng ri&ecirc;ng ảo, Virtual Private Network, l&agrave; một c&ocirc;ng nghệ mạng gi&uacute;p tạo kết nối mạng an to&agrave;n khi tham gia v&agrave;o mạng c&ocirc;ng cộng như Internet hoặc mạng ri&ecirc;ng do một nh&agrave; cung cấp dịch vụ sở hữu. C&aacute;c tập đo&agrave;n lớn, c&aacute;c cơ sở gi&aacute;o dục v&agrave; cơ quan ch&iacute;nh phủ sử dụng c&ocirc;ng nghệ VPN để cho ph&eacute;p người d&ugrave;ng từ xa kết nối an to&agrave;n đến mạng ri&ecirc;ng của cơ quan m&igrave;nh.</p>\r\n\r\n<p><img alt=\"Những lưu ý về bảo mật khi làm việc với máy tính tại nhà mà bạn nên biết - Ảnh 6.\" id=\"img_170356154411520000\" src=\"https://genk.mediacdn.vn/139269124445442048/2020/4/3/6-1585880070029351441820.png\" title=\"Những lưu ý về bảo mật khi làm việc với máy tính tại nhà mà bạn nên biết - Ảnh 6.\" /></p>\r\n\r\n<p>Khi kết nối m&aacute;y t&iacute;nh hoặc một thiết bị kh&aacute;c chẳng hạn như điện thoại, m&aacute;y t&iacute;nh bảng với một VPN, m&aacute;y t&iacute;nh hoạt động giống như n&oacute; nằm tr&ecirc;n c&ugrave;ng mạng nội bộ với VPN. Tất cả traffic tr&ecirc;n mạng được gửi qua kết nối an to&agrave;n đến VPN. Nhờ đ&oacute;, bạn c&oacute; thể truy cập an to&agrave;n đến c&aacute;c t&agrave;i nguy&ecirc;n mạng nội bộ ngay cả khi đang ở rất xa.</p>\r\n\r\n<p>Dịch vụ VPN c&aacute; nh&acirc;n chủ yếu bảo vệ quyền ri&ecirc;ng tư của người d&ugrave;ng chứ kh&ocirc;ng bảo vệ dữ liệu người d&ugrave;ng khỏi c&aacute;c phần mềm độc hại.</p>\r\n\r\n<p>5. Cảnh gi&aacute;c với c&aacute;c email, th&ocirc;ng b&aacute;o lạ</p>\r\n\r\n<p>Tương tự c&aacute;c tin giả về Covid-19, bạn cũng n&ecirc;n cảnh gi&aacute;c với những tin nhắn đ&aacute;ng ngờ của tin tặc v&agrave; c&aacute;c th&agrave;nh phần lừa đảo. Theo Microsoft, 91% c&aacute;c cuộc tấn c&ocirc;ng tr&ecirc;n Internet bắt đầu bằng một email độc hại. Một số c&oacute; thể hứa hẹn gửi đến bạn những th&ocirc;ng tin quan trọng về dịch bệnh nhưng tr&ecirc;n thực tế, khi bạn nhấp chuột v&agrave;o đường link hoặc tải tập tin về, đ&oacute; l&agrave; một phần mềm ăn cắp dữ liệu. M&aacute;y t&iacute;nh ngay lập tức bị tấn c&ocirc;ng, người d&ugrave;ng c&oacute; thể mất quyền kiểm so&aacute;t.</p>', 'ttcn5.jpg', 0, '2020-04-28 15:32:25', '2020-04-28 15:32:25', 'Nguyễn Quí Hổ');
INSERT INTO `news` (`id`, `id_cat`, `status`, `title`, `introduce`, `content`, `image`, `views`, `created_at`, `updated_at`, `created_by`) VALUES
(21, 3, 1, 'Cách xử lý tình trạng văn bản Office không thể đọc được trên mọi máy tính', NULL, '<p><span style=\"font-size:20px\"><strong>C&aacute;ch xử l&yacute; t&igrave;nh trạng văn bản Office kh&ocirc;ng thể đọc được tr&ecirc;n mọi m&aacute;y t&iacute;nh</strong></span><br />\r\nTrong qu&aacute; tr&igrave;nh soạn thảo c&aacute;c văn bản word, nhiều người vẫn gặp phải sự cố văn bản Office được soạn thảo tr&ecirc;n c&aacute;c m&aacute;y t&iacute;nh thế hệ mới &ndash; chạy Windows 7 hay Windows 8 vốn hầu hết đ&atilde; c&agrave;i đặt Office 2010 lại bị &ldquo;tắc tị&rdquo;, kh&ocirc;ng thể mở đọc được ở c&aacute;c m&aacute;y thế hệ cũ c&agrave;i đặt Office 2003.<br />\r\nThật ra đ&acirc;y kh&ocirc;ng phải lỗi, m&agrave; đ&acirc;y l&agrave; một sự cố tương th&iacute;ch phi&ecirc;n bản m&agrave; th&ocirc;i. Hiện nay, bộ c&ocirc;ng cụ văn ph&ograve;ng Microsoft Office 2007 v&agrave; 2010 đ&atilde; phổ biến hơn nhiều, nhưng phần lớn m&aacute;y t&iacute;nh &ndash; đặc biệt l&agrave; số m&aacute;y thế hệ cũ chạy Windows XP, vẫn c&ograve;n c&agrave;i đặt Office 2003. L&yacute; do chủ yếu l&agrave; người d&ugrave;ng đ&atilde; qu&aacute; quen với phi&ecirc;n bản cũ n&agrave;y, kh&ocirc;ng muốn thay đổi, hoặc nhu cầu họ rất đơn giản &ndash; chỉ cần soạn văn bản b&igrave;nh thường.</p>\r\n\r\n<p>Nguy&ecirc;n nh&acirc;n của sự cố n&agrave;y l&agrave; do Microsoft Office 2007 v&agrave; 2010 sử dụng định dạng file mới c&oacute; th&ecirc;m chữ x ở cuối phần mở rộng của file (đu&ocirc;i c&oacute; dạng như: .docx, .xlsx, .pptx). Định dạng Office mới n&agrave;y tất nhi&ecirc;n l&agrave; ti&ecirc;n tiến hơn, hỗ trợ nhiều t&iacute;nh năng hơn, v&agrave; đặc biệt l&agrave; c&oacute; dung lượng file nhỏ hơn. Nhưng điều bất tiện l&agrave; c&aacute;c định dạng Office mới n&agrave;y kh&ocirc;ng thể mở được ở c&aacute;c phiến bản Office từ 2003 trở về trước (trong khi c&aacute;c Office từ 2007 trở về sau n&agrave;y vẫn hỗ trợ c&aacute;c văn bản của c&aacute;c phi&ecirc;n bản trước).</p>\r\n\r\n<p>Ngay từ sau khi ph&aacute;t h&agrave;nh Office 2007, Microsoft đ&atilde; gi&uacute;p khắc phục sự cố tương th&iacute;ch n&agrave;y bằng c&aacute;ch đưa ra một c&ocirc;ng cụ tương th&iacute;ch miễn ph&iacute;&nbsp;Microsoft Office Compatibility Pack&nbsp;để bổ sung khả năng hỗ trợ c&aacute;c định dạng Office mới cho c&aacute;c phi&ecirc;n bản Office từ 2003 trở về trước. Ngặt một c&aacute;i, kh&ocirc;ng phải ai cũng quan t&acirc;m hay biết tới c&aacute;i giải ph&aacute;p n&agrave;y.</p>\r\n\r\n<p>V&igrave; thế, giải ph&aacute;p khả thi nhất khi muốn c&aacute;c văn bản Office m&agrave; bạn soạn thảo c&oacute; thể đọc được tr&ecirc;n bất cứ m&aacute;y t&iacute;nh n&agrave;o, d&ugrave; cũ hay mới, l&agrave; bạn lưu file với định dạng cũ (Office 97/2003). Cũng như với c&aacute;c phi&ecirc;n bản Office trước đ&oacute;, c&aacute;c phi&ecirc;n bản Office 2007 trở đi đều cho ph&eacute;p bạn chọn định dạng file để lưu, trong đ&oacute; c&oacute; Office 97-2003 Document, gọi l&agrave; chế độ tương th&iacute;ch Compatibility Mode.</p>\r\n\r\n<p>Sau khi soạn thảo xong văn bản ở Office 2007/2010, thay v&igrave; chọn Save (n&oacute; sẽ tự động save theo định dạng mặc định l&agrave; văn bản Office 2007/2010) tr&ecirc;n thẻ File, bạn chọn mục&nbsp;Save As.<br />\r\n&nbsp;</p>\r\n\r\n<p><img alt=\"\" src=\"http://vksbacninh.gov.vn/DATA/0/2017/01/2809947-09_02_48_988.png\" style=\"width:500px\" /></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Tr&ecirc;n m&agrave;n h&igrave;nh Save As, bạn đặt t&ecirc;n file rồi click chuột l&ecirc;n n&uacute;t mũi t&ecirc;n cuối hộp Save as type v&agrave; chọn trong danh s&aacute;ch định dạng&nbsp;Word 97-2003 Document. (Lưu &yacute; coi chừng nhầm với định dạng Word 97-2003 Template). Ở đ&acirc;y t&ocirc;i minh họa bằng Word 2010, với c&aacute;c c&ocirc;ng cụ Office kh&aacute;c, thao t&aacute;c cũng tương tự.<br />\r\n&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"\" src=\"http://vksbacninh.gov.vn/DATA/0/2017/01/2809948-09_02_49_222.png\" style=\"width:500px\" /></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Nhưng thao t&aacute;c n&agrave;y chỉ th&iacute;ch hợp khi l&acirc;u l&acirc;u bạn mới lưu file theo định dạng cũ. C&ograve;n nếu phải thường xuyện d&ugrave;ng định dạng Office 97/2003, bạn n&ecirc;n thiết đặt cho định dạng cũ n&agrave;y trở th&agrave;nh định dạng mặc định (default)&nbsp;Micro soft word lưu file dưới dạng đu&ocirc;i &quot;.doc&quot; để chỉ cần nhấn n&uacute;t Save b&igrave;nh thường l&agrave; Office sẽ tự động lưu file với định dạng tương th&iacute;ch.</p>\r\n\r\n<p>Để l&agrave;m điều n&agrave;y, bạn click chuột l&ecirc;n thẻ File, chọn mục&nbsp;Options&nbsp;tr&ecirc;n danh s&aacute;ch xổ xuống.<br />\r\n&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"\" src=\"http://vksbacninh.gov.vn/DATA/0/2017/01/2809949-09_02_49_409.png\" style=\"width:500px\" /></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Tr&ecirc;n m&agrave;n h&igrave;nh Office Options (trong b&agrave;i n&agrave;y ta d&ugrave;ng Word n&ecirc;n sẽ c&oacute; Word Options), bạn click chọn mục Save. Ở cột b&ecirc;n phải, tr&ecirc;n phần Save documents, bạn click l&ecirc;n n&uacute;t mũi t&ecirc;n ở cuối hộp Save files in this format (lưu c&aacute;c file với định dạng n&agrave;y), v&agrave; chọn trong danh s&aacute;ch định dạng Word 97-2003 Document. Nhấn n&uacute;t OK để ho&agrave;n tất.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"\" src=\"http://vksbacninh.gov.vn/DATA/0/2017/01/2809950-09_02_49_518.png\" style=\"width:500px\" /></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Kể từ nay, Office 2007 trở về sau sẽ tự động lưu c&aacute;c t&agrave;i liệu với định dạng Office 97-2003 c&oacute; thể mở được ở c&aacute;c m&aacute;y t&iacute;nh cũ v&agrave; mới.</p>\r\n\r\n<p>Lưu &yacute;: Nếu kh&ocirc;ng để ở chế độ mặc định lưu file dưới dạng file (.doc) th&igrave; khi c&agrave;i tiện &iacute;ch hỗ trợ đọc file (.docx) tr&ecirc;n office 2003 th&igrave; cần lưu file dưới t&ecirc;n kh&ocirc;ng c&oacute; dấu trong thư mục kh&ocirc;ng c&oacute; dấu để tr&aacute;nh lỗi xảy ra.</p>', 'tt.png', 0, '2020-04-28 15:36:40', '2020-04-28 15:36:40', 'Nguyễn Quí Hổ'),
(22, 3, 1, 'Các phím tắt trong Word, mà bạn nên biết', NULL, '<p><span style=\"font-size:20px\"><strong>C&aacute;c ph&iacute;m tắt trong Word, m&agrave; bạn n&ecirc;n biết</strong></span><br />\r\nĐể tiết kiệm thời gian v&agrave; đạt hiệu quả cao trong việc soạn thảo văn bản bằng Microsoft Word, thay v&igrave; sử dụng c&aacute;c thao t&aacute;c chuột để di chuyển c&aacute;c chức năng c&oacute; sẵn th&igrave; bạn n&ecirc;n sử dụng c&aacute;c ph&iacute;m tắt với chức năng cơ bản nhất để sử dụng h&agrave;ng ng&agrave;y.<br />\r\nMenu &amp; Toolbars</p>\r\n\r\n<p>Alt, F10: Mở menu lệnh<br />\r\nCtrl + Tab, Ctrl + Shift + Tab: Thực hi&ecirc;n ngay khi thanh Menu được k&iacute;ch hoạt để chọn c&aacute;c thanh menu v&agrave; thanh c&ocirc;ng cụ.<br />\r\nTab, Shift + Tab: Chọn c&aacute;c t&iacute;nh năng kế tiếp tr&ecirc;n thanh c&ocirc;ng cụ.<br />\r\nEnter: Mở lệnh đang chọn tr&ecirc;n Menu hoặc Toolbar.<br />\r\nAlt + Spacebar: Hiển thị Menu hệ thống.<br />\r\nHome, End: Chọn lệnh đầu ti&ecirc;n hoặc cuối c&ugrave;ng trong Menu con.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>* Tạo, Chỉnh Sửa V&agrave; Lưu Văn Bản</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Ctrl + N: Tạo văn bản mới.<br />\r\nCtrl + O: Mở một văn bản mới đ&atilde; được soạn thảo trước đ&oacute;.<br />\r\nCtrl + S: Lưu văn bản soạn thảo.<br />\r\nCtrl + C: Sao ch&eacute;p văn bản.<br />\r\nCtrl + X: Cắt một nội dung bất k&igrave; trong văn bản.<br />\r\nCtrl + V: D&aacute;n văn bản.<br />\r\nCtrl + F: T&igrave;m kiếm từ/cụm từ hoặc đoạn văn bản.<br />\r\nCtrl + H: Chức năng thay thế, thay thế một từ/cụm từ bằng một từ/cụm từ kh&aacute;c.<br />\r\nCtrl + P: In ấn văn bản.<br />\r\nCtrl + Z: Trở lại trạng th&aacute;i văn bản trước khi thực hiện lần chỉnh sửa cuối c&ugrave;ng.<br />\r\nCtrl + Y: Phục hồi trạng th&aacute;i văn bản trước khi sử dụng lệnh Ctrl+Z.<br />\r\nCtrl + F4 , Ctrl + W, Alt + F4: Đ&oacute;ng lại văn bản.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>* Chọn Đoạn Văn Bản Hoặc Một Đối Tượng N&agrave;o Đ&oacute;.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>- Di chuyển, chọn đoạn văn</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Shift + &ndash;&gt;: Di chuyển con trỏ chuột đến k&iacute; tự ph&iacute;a sau.<br />\r\nShift + &lt;&ndash;: Di chuyển con trỏ chuột đến k&iacute; tự ph&iacute;a trước.<br />\r\nCtrl + Shift + &ndash;&gt;: Di chuyển con trỏ chuột đến một từ đằng sau.<br />\r\nCtrl + Shift + &lt;&ndash;: Di chuyển con trỏ chuột đến một từ đằng trước.<br />\r\nShift + (mũi t&ecirc;n hướng l&ecirc;n): Di chuyển con trỏ chuột đến h&agrave;ng tr&ecirc;n<br />\r\nShift + (mủi t&ecirc;n hướng xuống): Di chuyển con trỏ chuột xuống h&agrave;ng dưới.<br />\r\nCtrl + A: Chọn to&agrave;n bộ văn bản.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>- X&oacute;a đoạn văn bản hoặc một đối tượng</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Backspace: X&oacute;a một k&iacute; tự ph&iacute;a trước.<br />\r\nCtrl + Backspace : X&oacute;a k&iacute; tự ph&iacute;a trước.<br />\r\nDelete: X&oacute;a k&iacute; tự ph&iacute;a sau con trỏ chuột hoặc một đối tượng n&agrave;o đ&oacute;.<br />\r\nCtrl + Delete: X&oacute;a một từ ở ngay ph&iacute;a sau con trỏ chuột.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>- Di chuyển đoạn văn bản</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Ctrl + Ph&iacute;m mũi t&ecirc;n bất k&igrave; : Di chuyển qua lại giữa c&aacute;c k&iacute; tự.<br />\r\nCtrl + Home: Di chuyển chuột về đầu đoạn văn bản<br />\r\nCtrl + End: Di chuyển con trỏ chuột về vị tr&iacute; cuối c&ugrave;ng trong văn bản<br />\r\nCtrl + Shift + Home: Di chuyển chuột từ vị tr&iacute; hiện tại đến đầu văn bản.<br />\r\nCtrl + Shift + End: Di chuyển chuột từ vị tr&iacute; hiện tại đến cuối văn bản.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>- Định dạng văn bản</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Ctrl + B: In đậm.<br />\r\nCtrl + D: Mở hộp thoại thay đổi font chữ.<br />\r\nCtrl + I: In nghi&ecirc;ng.<br />\r\nCtrl + U: Gạch ch&acirc;n.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>- Căn lề đoạn văn bản</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Ctrl + E: Căn chỉnh đoạn văn bản đang chọn tại vị tr&iacute; trung t&acirc;m.<br />\r\nCtrl + J: Căn chỉnh đều cho văn bản.<br />\r\nCtrl + L: Căn tr&aacute;i cho văn bản.<br />\r\nCtrl + R: Căn phải cho văn bản.<br />\r\nCtrl + M: L&ugrave;i đầu d&ograve;ng đoạn văn bản.<br />\r\nCtrl + Shift + M: X&oacute;a định dạng Ctrl + M<br />\r\nCtrl + T: L&ugrave;i đoạn văn bản 2 d&ograve;ng trở đi.<br />\r\nCtrl + Shift + T: X&oacute;a định dạng Ctrl + T.<br />\r\nCtrl + Q: X&oacute;a định dạng canh lề đoạn văn bản</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>* Sao Ch&eacute;p Định Dạng Văn Bản</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Ctrl + Shift + C: Sao ch&eacute;p đoạn văn đang c&oacute; định dạng cần sao ch&eacute;p.<br />\r\nCtrl + Shift + V: D&aacute;n định dạng đ&atilde; sao ch&eacute;p v&agrave;o v&ugrave;ng dữ liệu đang chọn.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>* Tạo Số Mũ</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Ctrl + Shift + =: Tạo số mũ, v&iacute; dụ H2</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Ctrl + =: Tạo số mũ ở dưới (thường d&ugrave;ng cho c&aacute;c k&iacute; hiệu h&oacute;a học), v&iacute; dụ H2O</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>* L&agrave;m Việc Tr&ecirc;n C&aacute;c Bảng Biểu</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Tab: &nbsp;Di chuyển v&agrave; chọn nội dung của &ocirc; bảng biểu kế tiếp hoặc tạo một d&ograve;ng mới nếu đang ở &ocirc; cuối c&ugrave;ng trong bảng.<br />\r\nShift + Tab: Di chuyển con trỏ chuột tới nội dung của &ocirc; liền kề.<br />\r\nShift + c&aacute;c ph&iacute;m mũi t&ecirc;n: Chọn nội dung của &ocirc; liền kề ngay vị tr&iacute; đang chọn.<br />\r\nCtrl + Shift + F8 + C&aacute;c ph&iacute;m mũi t&ecirc;n: Mở rộng v&ugrave;ng chọn theo từng &ocirc; bảng biểu.<br />\r\nShift + F8: Thu nhỏ k&iacute;ch thước v&ugrave;ng chọn theo từng &ocirc;.<br />\r\nCtrl + 5 (khi đ&egrave;n Num Lock tắt): Chọn nội dung của to&agrave;n bộ &ocirc; bảng biểu.<br />\r\nAlt + Home: Về &ocirc; đầu ti&ecirc;n của bảng biểu<br />\r\nAlt + End: Về &ocirc; cuối c&ugrave;ng của d&ograve;ng hiện tại.<br />\r\nAlt + Page up: Trở lại &ocirc; bảng biểu đầu ti&ecirc;n của cột.<br />\r\nAlt + Page down: Trở lại &ocirc; bảng biểu cuối c&ugrave;ng của cột.<br />\r\nMũi t&ecirc;n l&ecirc;n: Di chuyển con trỏ chuột l&ecirc;n tr&ecirc;n một d&ograve;ng<br />\r\nMũi t&ecirc;n xuống: Di chuyển con trỏ chuột xuống dưới một d&ograve;ng.</p>\r\n\r\n<p>&nbsp;</p>', 'Microsoft-Word-2013.jpg', 0, '2020-04-28 15:38:37', '2020-04-28 15:38:37', 'Nguyễn Quí Hổ'),
(23, 3, 1, 'Một số kinh nghiệm bảo mật thông tin trên mạng Internet', NULL, '<p><span style=\"font-size:20px\"><strong>Một số kinh nghiệm bảo mật th&ocirc;ng tin tr&ecirc;n mạng Internet</strong></span><br />\r\nVấn đề bảo mật th&ocirc;ng tin n&oacute;i chung v&agrave; bảo mật th&ocirc;ng tin tr&ecirc;n mạng Internet l&agrave; v&ocirc; c&ugrave;ng rộng lớn v&agrave; phức tạp, trong phạm vi b&agrave;i viết n&agrave;y ch&uacute;ng t&ocirc;i chỉ n&ecirc;u l&ecirc;n một số kinh nghiệm trong việc bảo mật th&ocirc;ng tin tr&ecirc;n mạng Internet đối với người sử dụng m&aacute;y vi t&iacute;nh c&oacute; kết nối Internet để bạn đọc tham khảo, với mong muốn g&oacute;p phần bảo vệ b&iacute; mật th&ocirc;ng tin trong nội bộ ng&agrave;nh v&agrave; b&iacute; mật quốc gia.<br />\r\nNhững năm gần đ&acirc;y, với sự quan t&acirc;m của Đảng v&agrave; nh&agrave; nước đối với ng&agrave;nh kiểm s&aacute;t n&oacute;i chung v&agrave; sự quan t&acirc;m của L&atilde;nh đạo c&aacute;c cấp kiểm s&aacute;t, n&ecirc;n hầu hết c&aacute;c C&aacute;n bộ, Kiểm s&aacute;t vi&ecirc;n trong ng&agrave;nh kiểm s&aacute;t nh&acirc;n d&acirc;n đều được trang bị m&aacute;y vi t&iacute;nh, trong đ&oacute; phần lớn m&aacute;y vi t&iacute;nh đều được kết nối Internet, &nbsp;đồng thời rất nhiều đơn vị đ&atilde; cấp địa chỉ hộp thư điện tử cho c&aacute;c tập thể v&agrave; c&aacute; nh&acirc;n để bảo đảm việc trao đổi th&ocirc;ng tin trong nội bộ ng&agrave;nh. Sự quan t&acirc;m đầu tư đ&oacute;, đ&atilde; tạo điều kiện thuận lợi trong việc trao đổi th&ocirc;ng tin, n&acirc;ng cao hiệu quả họat động của ng&agrave;nh v&agrave; giảm đ&aacute;ng kể về thời gian v&agrave; kinh ph&iacute;.</p>\r\n\r\n<p>Tuy nhi&ecirc;n, b&ecirc;n cạnh những lợi &iacute;ch m&agrave; Internet mang lại, th&igrave; ch&uacute;ng ta cũng phải hiểu rằng, mặt tr&aacute;i của Internet l&agrave; c&aacute;c th&ocirc;ng tin b&iacute; mật rất dễ bị lộ lọt ra b&ecirc;n ngo&agrave;i. Lỗ hổng n&agrave;y cần phải được cảnh b&aacute;o v&agrave; c&oacute; biện ph&aacute;p khắc phục.</p>\r\n\r\n<p>Ng&agrave;nh kiểm s&aacute;t nh&acirc;n d&acirc;n được Đảng, nh&agrave; nước giao chức năng Thực h&agrave;nh quyền c&ocirc;ng tố v&agrave; kiểm s&aacute;t hoạt động tư ph&aacute;p; do t&iacute;nh chất đặc th&ugrave; của nhiệm vụ &ldquo; bảo vệ ph&aacute;p luật, bảo vệ quyền con người, quyền c&ocirc;ng d&acirc;n, bảo vệ chế độ x&atilde; hội chủ nghĩa, bảo vệ lợi &iacute;ch của Nh&agrave; nước, quyền v&agrave; lợi &iacute;ch hợp ph&aacute;p của tổ chức, c&aacute; nh&acirc;n, g&oacute;p phần bảo đảm ph&aacute;p luật được chấp h&agrave;nh nghi&ecirc;m chỉnh v&agrave; thống nhất&rdquo;. V&igrave; vậy, Ng&agrave;nh kiểm s&aacute;t phải lu&ocirc;n n&ecirc;u cao tr&aacute;ch nhiệm bảo vệ b&iacute; mật quốc gia; trong đ&oacute; c&oacute; bảo mật th&ocirc;ng tin tr&ecirc;n mạng Intrernet. Thực tế thời gian qua cho thấy, kh&ocirc;ng phải mọi tổ chức, c&aacute; nh&acirc;n trong ng&agrave;nh đều &yacute; thức được tầm quan trọng của bảo mật th&ocirc;ng tin v&agrave; am hiểu chế độ bảo mật. Ch&uacute;ng t&ocirc;i thấy, ở một số nơi hộp thư điện tử được cấp v&agrave; sử dụng qua nhiều năm, nhưng vẫn c&ograve;n c&oacute; tập thể hoặc c&aacute; nh&acirc;n đến nay vẫn giữ nguy&ecirc;n password (mật khẩu đăng nhập tư điện tử) được cấp lần đầu, m&agrave; chưa một lần được thay đổi hoặc chỉ được thay đổi một v&agrave;i lần, điều đ&oacute; chứng tỏ nhận thức của ch&uacute;ng ta về vấn đề bảo mật th&ocirc;ng tin tr&ecirc;n mạng Intrernet c&ograve;n nhiều hạn chế.</p>\r\n\r\n<p>Để khắc phục những thiếu s&oacute;t tr&ecirc;n, sau đ&acirc;y ch&uacute;ng t&ocirc;i xin gợi &yacute; một số biện ph&aacute;p bảo mật th&ocirc;ng tin tr&ecirc;n mạng Internet để bạn đọc tham khảo.</p>\r\n\r\n<p>- Vấn đề bảo mật th&ocirc;ng tin tr&ecirc;n mạng Internet l&agrave; vấn đề v&ocirc; c&ugrave;ng quan trọng, nhạy cảm, v&agrave; kh&oacute; thực hiện, v&igrave; vậy đối với những người c&oacute; kiến thức v&agrave; kinh nghiệm sử dụng m&aacute;y t&iacute;nh v&agrave; mạng m&aacute;y t&iacute;nh, n&ecirc;n t&igrave;m hiểu v&aacute; &aacute;p dụng c&aacute;c c&aacute;ch thức bảo mật được đăng tải tr&ecirc;n mạng Intrernet (chỉ cần v&agrave;o c&ocirc;ng cụ t&igrave;m kiếm tr&ecirc;n Intrernet g&otilde; từ kh&oacute;a &ldquo; bảo đảm b&iacute; mật th&ocirc;ng tin&rdquo; đ&atilde; c&oacute; gần 1 triệu b&agrave;i viết về vấn đề n&agrave;y), trong đ&oacute; c&oacute; nhiều b&agrave;i viết gi&uacute;p ch&uacute;ng ta n&acirc;ng cao nhận thức v&agrave; c&aacute;ch thức thực hiện bảo mật cho chiếc m&aacute;y vi t&iacute;nh của m&igrave;nh;</p>\r\n\r\n<p>- Đối với những người chưa c&oacute; nhiều kinh nghiệm hoặc kiến thức về c&ocirc;ng nghệ th&ocirc;ng tin th&igrave; n&ecirc;n thực hiện theo c&aacute;c c&aacute;ch đơn giản sau đ&acirc;y:</p>\r\n\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; + Đặt mật khẩu cho m&aacute;y vi t&iacute;nh (password): Mật khẩu cho m&aacute;y phải đủ mạnh, bao gồm cả chữ c&aacute;i, số, k&yacute; tự đặc biệt. Kh&ocirc;ng n&ecirc;n d&ugrave;ng c&aacute;c số, hoặc chữ đơn giản l&agrave;m mật khẩu như ng&agrave;y sinh, số chứng minh nh&acirc;n d&acirc;n, biển số xe, t&ecirc;n người, t&ecirc;n địa danh vv&hellip; sẽ rất dễ bị ph&aacute;t hiện (trường hợp n&agrave;y &aacute;p dụng cả với việc đặt mật khẩu cho Wifi (thiết bị kết nối kh&ocirc;ng d&acirc;y), v&agrave; c&aacute;c loại mật khẩu kh&aacute;c;</p>\r\n\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; + Kh&ocirc;ng soạn thảo văn bản tr&ecirc;n m&aacute;y vi t&iacute;nh c&oacute; kết nối Intrernet (điều n&agrave;y rất kh&oacute; thực hiện, do hiện nay c&aacute;c m&aacute;y vi t&iacute;nh c&aacute; nh&acirc;n đều được kết nối Intrernet). Tuy nhi&ecirc;n, c&oacute; một c&aacute;ch khắc phục đơn giản m&agrave; hiệu quả, đ&oacute; l&agrave;: Khi soạn thảo văn bản mật th&igrave; phải ngắt kết nối Intrernet bằng c&aacute;ch r&uacute;t cab mạng ra khỏi m&aacute;y vi t&iacute;nh hoặc tắt kết nối wifi (nếu sử dụng mạng kh&ocirc;ng d&acirc;y), sau khi soạn thảo văn bản xong, in ra giấy để lưu trữ th&igrave; x&oacute;a file văn bản trong m&aacute;y vi t&iacute;nh;</p>\r\n\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; + Thường xuy&ecirc;n diệt virus tr&ecirc;n m&aacute;y vi t&iacute;nh (nếu kh&ocirc;ng c&oacute; phần mềm bản quyền diệt virus th&igrave; n&ecirc;n thường xuy&ecirc;n cập nhật phần mềm miễn ph&iacute; tại địa chỉ www.bkav.com.vn hoặc c&aacute;c địa chỉ kh&aacute;c để diệt virus). K&iacute;ch hoạt v&agrave; thiết lập chức năng tường lửa tr&ecirc;n c&aacute;c m&aacute;y vi t&iacute;nh c&aacute; nh&acirc;n v&agrave; chế độ tự động cập nhật bản v&aacute; lỗ hổng bảo mật để ngăn chặn sự x&acirc;m nhập tr&aacute;i ph&eacute;p từ b&ecirc;n ngo&agrave;i;</p>\r\n\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; + Tập th&oacute;i quen ngắt kết nối Intrernet bằng c&aacute;ch r&uacute;t d&acirc;y Cab mạng ra khỏi m&aacute;y vi t&iacute;nh, hoặc tắt wifi trong khi kh&ocirc;ng truy cập mạng Intrernet;</p>\r\n\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; + Kh&ocirc;ng mở c&aacute;c trang Web, c&aacute;c quản c&aacute;o, c&aacute;c tin nhắn, thư điện tử kh&ocirc;ng r&otilde; nguồn gốc (Spam), nhất l&agrave; c&aacute;c trang Web &ldquo;nhạy cảm&rdquo;, c&aacute;c quảng c&aacute;o &ldquo;bắt mắt&rdquo;, c&aacute;c thư điện tử &ldquo;mời ch&agrave;o hấp dẫn&rdquo;, đ&acirc;y thường l&agrave; những c&aacute;i bẫy của tin tặc c&agrave;i cấy virus, m&atilde; độc v&agrave;o m&aacute;y vi t&iacute;nh nhằm mục đ&iacute;ch đ&aacute;nh cắp th&ocirc;ng tin;</p>\r\n\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; + Kh&ocirc;ng sao lưu file dữ liệu mật v&agrave;o c&aacute;c thiết bị di động như: ổ cứng ngo&agrave;i, USB, thẻ nhớ, v&igrave; v&aacute;c thiết bị n&agrave;y rất dễ bị đ&aacute;nh cắp hoặc bị thất lạc;</p>\r\n\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; + Chỉ nhận, gửi văn bản qua hộp thư điện tử của ng&agrave;nh đ&atilde; cấp cho c&aacute;c tập thể, c&aacute; nh&acirc;n; kh&ocirc;ng được gửi, nhận văn bản th&ocirc;ng qua c&aacute;c hộp thư điện tử miễn ph&iacute; như c&aacute;c hộp thư của yahoo, gmail&hellip;;</p>\r\n\r\n<p>- Việc bảo mật thư điện tử: Thư điện tử hiện nay trở n&ecirc;n phổ biến, l&agrave; c&ocirc;ng cụ quan trọng trong việc trao đổi th&ocirc;ng tin, v&igrave; vậy ch&uacute;ng ta cần ch&uacute; &yacute;:</p>\r\n\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; + Đặt mật khẩu đủ mạnh (như đ&atilde; n&ecirc;u ở phần tr&ecirc;n); thường xuy&ecirc;n thay đổi mật khẩu (thay đổi h&agrave;ng tuần, h&agrave;ng th&aacute;ng hoặc khi ph&aacute;t hiện nguy cơ bị lộ mật khẩu). Kh&ocirc;ng lưu mật khẩu tr&ecirc;n m&aacute;y vi t&iacute;nh, điện thoại di động, Ipas để tr&aacute;nh bị lộ mật khẩu.</p>\r\n\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; + Sau khi gửi hoặc nhận văn bản qua thư điện tử, th&ocirc;ng tin mật phải in ra giấy để lưu trữ v&agrave; x&oacute;a ngay tr&ecirc;n hộp thư (ở cả mục nhận thư v&agrave; gửi thư).</p>\r\n\r\n<p>- Khi sửa chữa m&aacute;y vi t&iacute;nh c&oacute; lưu giữ th&ocirc;ng tin, nhất thiết kh&ocirc;ng được để kỹ thuật vi&ecirc;n đem m&aacute;y đi nơi kh&aacute;c ngo&agrave;i cơ quan để sửa chữa; phải cử người gi&aacute;m s&aacute;t việc sửa chữa tại nơi l&agrave;m việc;</p>\r\n\r\n<p>- Khi thanh l&yacute; m&aacute;y vi t&iacute;nh phải x&oacute;a to&agrave;n bộ dữ liệu tr&ecirc;n m&aacute;y (tốt nhất, l&agrave; kh&ocirc;ng thanh l&yacute; ổ cứng của m&aacute;y) để bảo đảm chắc chắn th&ocirc;ng tin kh&ocirc;ng bị đưa ra ngo&agrave;i;</p>\r\n\r\n<p>- Tr&ecirc;n đ&acirc;y l&agrave; một v&agrave;i kinh nghiệm của t&aacute;c giả, bạn đọc c&oacute; thể t&igrave;m hiểu th&ecirc;m từ c&aacute;c nguồn t&agrave;i liệu kh&aacute;c để vận dụng, gi&uacute;p cho việc bảo mật th&ocirc;ng tin được tốt hơn.</p>', 'tt3.jpg', 0, '2020-04-28 15:40:44', '2020-04-28 15:40:44', 'Nguyễn Quí Hổ'),
(24, 3, 1, 'Khóa một cột, một dòng, một ô hoặc một vùng trong Excel', NULL, '<h1>Kh&oacute;a một cột, một d&ograve;ng, một &ocirc; hoặc một v&ugrave;ng trong Excel</h1>\r\n\r\n<p>Tối h&ocirc;m qua d&agrave;nh thời gian thử dịch vụ fetch.io để giới thiệu với mọi người nhưng đ&aacute;ng tiếc l&agrave; đ&atilde; thất bại. C&oacute; lẽ bởi v&igrave; n&oacute; đang trong giai đoạn beta n&ecirc;n bị đi&ecirc;n, l&agrave;m m&igrave;nh d&ugrave;ng thử cũng muốn kh&ugrave;ng với n&oacute; !</p>\r\n\r\n<p><br />\r\nH&ocirc;m nay, t&ocirc;i v&agrave; một anh bạn c&ugrave;ng nhau t&igrave;m hiểu một vấn đề sau khi c&oacute; &ldquo;lệnh&rdquo; : &ldquo;C&aacute;i cột n&agrave;y (1 cột trong Excel) phải l&agrave;m c&aacute;ch n&agrave;o đ&oacute; kh&oacute;a n&oacute; lại, kh&ocirc;ng để người d&ugrave;ng thay đổi nội dung&hellip;&rdquo;</p>\r\n\r\n<p>Thế l&agrave; &ldquo;Google thẳng tiến&rdquo; với c&aacute;c từ kh&oacute;a li&ecirc;n quan đến việc kh&oacute;a một cột n&agrave;o đ&oacute; trong file Excel ! Sau một hồi t&igrave;m kiếm v&agrave; li&ecirc;n tục&hellip;thất bại, ch&uacute;ng t&ocirc;i đ&atilde; t&igrave;m được c&aacute;ch l&agrave;m như sau :<br />\r\n&ndash; Mở kh&oacute;a (unlock) to&agrave;n bộ sheet hiện tại : đ&acirc;y l&agrave; bước quan trọng nhất nhưng &iacute;t được chỉ dẫn n&ecirc;n dẫn đến thất bại :dapdau: . Bạn bấm Ctrl+A để chọn hết phần nội dung. Tiếp theo nhấp chuột phải v&agrave;o &ocirc; bất kỳ v&agrave; chọn &ldquo;Format cells&hellip;&rdquo; như h&igrave;nh b&ecirc;n dưới.</p>\r\n\r\n<p><img alt=\"LockExcelRowColumn1\" src=\"http://vksbacninh.gov.vn/DATA/OLD/images/CNTT/LockExcelRowColumn1.jpg\" style=\"height:447px; width:588px\" /></p>\r\n\r\n<p>&ndash; Hộp thoại hiện ra, bạn chọn thẻ Protection v&agrave; sẽ thấy mục &ldquo;Locked&rdquo; đ&atilde; được chọn sẵn. Bạn nhấp v&agrave;o đ&oacute; để bỏ chọn, xong bấm OK.</p>\r\n\r\n<p><img alt=\"LockExcelRowColumn2\" src=\"http://vksbacninh.gov.vn/DATA/OLD/images/CNTT/LockExcelRowColumn2.jpg\" style=\"height:159px; width:538px\" /></p>\r\n\r\n<p>&ndash; Bạn c&oacute; thể kh&oacute;a một cột, một d&ograve;ng, một &ocirc; hoặc một v&ugrave;ng bất kỳ trong Excel bằng c&aacute;ch x&aacute;c định v&ugrave;ng cần kh&oacute;a, sau đ&oacute; lặp lại bước đầu ti&ecirc;n nhưng chỉ cho v&ugrave;ng cần kh&oacute;a. Tức l&agrave; bạn nhấp chuột phải v&agrave;o v&ugrave;ng cần kh&oacute;a (ở đ&acirc;y t&ocirc;i sẽ kh&oacute;a to&agrave;n bộ cột A của file Excel) v&agrave; chọn &ldquo;Format cells&hellip;&rdquo; -&gt; &ocirc; hiện ra chọn thẻ &ldquo;Protection&rdquo; v&agrave; check v&agrave;o t&ugrave;y chọn &ldquo;Locked&rdquo; (ở bước đầu ti&ecirc;n l&agrave; bỏ chọn n&oacute;, bước n&agrave;y th&igrave; l&agrave;m ngược lại).</p>\r\n\r\n<p>&ndash; Tiếp theo chọn thẻ Review (Excel 2007) -&gt; bấm n&uacute;t &ldquo;Protect Sheet&rdquo; -&gt; hộp thoại hiện ra bạn nhập mật khẩu v&agrave;o &ocirc; &ldquo;Password&hellip;&rdquo;. Ở phần b&ecirc;n dưới của hộp thoại, bạn sẽ thấy một danh s&aacute;ch c&aacute;c t&ugrave;y chọn. Đ&acirc;y ch&iacute;nh l&agrave; những g&igrave; m&agrave; người d&ugrave;ng c&oacute; thể l&agrave;m được : mặc định sau khi kh&oacute;a, người d&ugrave;ng vẫn c&oacute; thể chọn nội dung của v&ugrave;ng bị kh&oacute;a (Select locked cells) v&agrave; chọn nội dung của v&ugrave;ng kh&ocirc;ng bị kh&oacute;a (Select unlicked cells). Nếu kh&ocirc;ng muốn người d&ugrave;ng đụng chuột v&agrave;o v&ugrave;ng bị kh&oacute;a th&igrave; bỏ chọn &ldquo;Select locked cells&rdquo;.</p>\r\n\r\n<p><img alt=\"LockExcelRowColumn3\" src=\"http://vksbacninh.gov.vn/DATA/OLD/images/CNTT/LockExcelRowColumn3.jpg\" style=\"height:143px; width:584px\" /></p>\r\n\r\n<p><img alt=\"LockExcelRowColumn4\" src=\"http://vksbacninh.gov.vn/DATA/OLD/images/CNTT/LockExcelRowColumn4.jpg\" style=\"height:314px; width:271px\" /></p>\r\n\r\n<p>&ndash; Sau khi chọn xong th&igrave; bấm OK -&gt; nhập lại mật khẩu v&agrave; bấm OK. Vậy l&agrave; xong, phần nội dung m&agrave; bạn chọn đ&atilde; bị kh&oacute;a v&agrave; kh&ocirc;ng thể bị chỉnh sửa.</p>\r\n\r\n<p>&ndash; Nếu muốn mở kh&oacute;a th&igrave; bấm chuột v&agrave;o &ldquo;Protect Sheet&rdquo; v&agrave; nhập v&agrave;o mật khẩu.</p>', 'tt4.jpg', 0, '2020-04-28 15:44:13', '2020-04-28 15:44:13', 'Nguyễn Quí Hổ'),
(25, 3, 1, 'Thao tác trộn thư, trộn văn bản trong Microsoft Word', NULL, '<h1>Thao t&aacute;c trộn thư, trộn văn bản trong Microsoft Word</h1>\r\n\r\n<p>Trộn thư l&agrave; t&iacute;nh năng hữu &iacute;ch trong Word, t&iacute;nh năng n&agrave;y cho ph&eacute;p bạn tiết kiệm được nhiều thời gian khi phải thao t&aacute;c với nhiều văn bản c&oacute; nội dung giống nhau dạng như ch&egrave;n danh s&aacute;ch v&agrave;o một t&agrave;i liệu cố định như thư mời, thư cảm ơn, giấy chứng nhận,&hellip; m&agrave; kh&ocirc;ng phải đ&aacute;nh lại nội dung của văn bản ban đầu.<br />\r\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Ở đ&acirc;y sẽ giới thiệu chi tiết c&aacute;ch trộn thư trong Microsoft word 2003 v&agrave; 2007</p>\r\n\r\n<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Đầu ti&ecirc;n, Soạn thảo file word gốc c&oacute; sẵn m&agrave; nội dung c&aacute;c văn bản đều giống nhau để ch&egrave;n th&ocirc;ng tin kh&aacute;c nhau v&agrave;o.</p>\r\n\r\n<p>1. Đối với Microsoft Word 2003 ta l&agrave;m như sau:</p>\r\n\r\n<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Bước 1: Mở file word cần trộn thư, sau đ&oacute; v&agrave;o&nbsp;Tools, chọn&nbsp;Letters and Mailings&nbsp;v&agrave; chọn tiếp&nbsp;Mail Merge&hellip;</p>\r\n\r\n<p><img alt=\"tron-thu-trong-word-1\" src=\"http://vksbacninh.gov.vn/DATA/OLD/images/CNTT/tron-thu-trong-word-1.jpg\" style=\"height:269px; width:422px\" /></p>\r\n\r\n<p><strong>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Bước 2: Tại khung Mail Merge xuất hiện b&ecirc;n ph&iacute;a tay phải trang word ta chọn Letters v&agrave; nhấn Next.</strong></p>\r\n\r\n<p><img alt=\"tron-thu-trong-word-2\" src=\"http://vksbacninh.gov.vn/DATA/OLD/images/CNTT/tron-thu-trong-word-2.jpg\" style=\"height:412px; width:203px\" /></p>\r\n\r\n<p><strong>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Bước 3</strong>: Chọn mục&nbsp;<strong>Use the current document</strong>&nbsp;v&agrave; tiếp tục nhấn&nbsp;<strong>Next</strong>.</p>\r\n\r\n<p><img alt=\"tron-thu-trong-word-3\" src=\"http://vksbacninh.gov.vn/DATA/OLD/images/CNTT/tron-thu-trong-word-3.jpg\" style=\"height:356px; width:200px\" /></p>\r\n\r\n<p><strong>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Bước 4: Chọn Use an existing list (d&ugrave;ng danh s&aacute;ch c&oacute; sẵn) v&agrave; nhấn Next. Bạn cũng c&oacute; thể tạo mới danh s&aacute;ch bằng c&aacute;ch nhấp v&agrave;o t&ugrave;y chọn Type a new list.</strong></p>\r\n\r\n<p><img alt=\"tron-thu-trong-word-4\" src=\"http://vksbacninh.gov.vn/DATA/OLD/images/CNTT/tron-thu-trong-word-4.jpg\" style=\"height:375px; width:202px\" /></p>', 'tt2.jpg', 0, '2020-04-28 15:45:26', '2020-04-28 15:45:26', 'Nguyễn Quí Hổ');

