INSERT INTO `notifi` (`id`, `title`, `content`, `created_at`, `updated_at`) VALUES
(1, 'Khuyến mãi khách hàng thân thuộc', '<p>Thực hiện chương tr&igrave;nh tri &acirc;n kh&aacute;ch h&agrave;ng th&acirc;n thuộc, TECHFAST xin gởi đến qu&yacute; kh&aacute;ch h&agrave;ng M&Atilde; GIẢM GI&Aacute; 10% gi&aacute; trị đơn h&agrave;ng. Để nhận ưu đ&atilde;i, qu&yacute; kh&aacute;ch vui l&ograve;ng nhập &quot;MGG10&quot;. Xin cảm ơn qu&yacute; kh&aacute;ch đ&atilde; ủng hộ ch&uacute;ng t&ocirc;i suốt thời gian vừa qua</p>', '2020-05-26 15:57:34', '2020-05-26 15:57:34'),
(2, 'MỪNG ĐẠI LỄ - ACER SALE SIÊU KHỦNG 30.4 & 1.5.2020', '<p>Thực hiện chương tr&igrave;nh tri &acirc;n kh&aacute;ch h&agrave;ng th&acirc;n thuộc, TECHFAST xin gởi đến qu&yacute; kh&aacute;ch h&agrave;ng M&Atilde; GIẢM GI&Aacute; 15% gi&aacute; trị đơn h&agrave;ng. Để nhận ưu đ&atilde;i, qu&yacute; kh&aacute;ch vui l&ograve;ng nhập &quot;MGG15&quot;. Xin cảm ơn qu&yacute; kh&aacute;ch đ&atilde; ủng hộ ch&uacute;ng t&ocirc;i suốt thời gian vừa qua</p>', '2020-05-26 16:00:33', '2020-05-26 16:00:33'),
(3, 'Khuyến mãi khách hàng thân thuộc', '<p>Thực hiện chương tr&igrave;nh tri &acirc;n kh&aacute;ch h&agrave;ng th&acirc;n thuộc, TECHFAST xin gởi đến qu&yacute; kh&aacute;ch h&agrave;ng M&Atilde; GIẢM GI&Aacute; 10% gi&aacute; trị đơn h&agrave;ng. Để nhận ưu đ&atilde;i, qu&yacute; kh&aacute;ch vui l&ograve;ng nhập &quot;MGG20&quot;. Xin cảm ơn qu&yacute; kh&aacute;ch đ&atilde; ủng hộ ch&uacute;ng t&ocirc;i suốt thời gian vừa qua</p>', '2020-05-26 16:01:14', '2020-05-26 16:01:14');

