(221, 'G102 Prodigy', 'Chuột máy tính Logitech G102', 20, NULL, 'Tên sản phẩm: Chuột máy tính Logitech G102 Prodigy Gaming (Đen)', 'Tên sản phẩm: Chuột máy tính Logitech G102 Prodigy Gaming (Đen)\r\n\r\n- DPI có sẵn : 400 - 800 - 1600 - 3200 (tối đa 8000dpi)- Có driver (Logitech Gaming Software) tuỳ chỉnh DPI, macro, led. - Có bộ nhớ trong tích hợp trên chuột để lưu các thiết lập.- Lift-off distance (khoảng cách nhận tín hiệu) : ~1.8 mm (pad vải), ~2mm (pad cứng). - Cảm biến MERCURY - một loại cảm biến quang học chất lượng cao được phát triển tại Hoa Kỳ.', 379000, 0, '160c.png', NULL, 0, 1000, '2020-04-27 14:35:42', '2020-04-27 14:35:42'),
(222, 'B100', 'Chuột máy tính Logitech B100', 20, NULL, 'Tên sản phẩm: Chuột máy tính Logitech B100', 'Tên sản phẩm: Chuột máy tính Logitech B100\r\n\r\n- Thiết đơn giản,dễ sử dụng cho người dùng- Công nghệ quang học đã được sử dụng trong chuột quang Logitech USB với độ phân giải 800 dpi.- Chất liệu nhựa chất lượng hàng đầu khiến nó có khả năng kéo dài trong một thời gian rất dài.', 75000, 0, '161c.png', NULL, 0, 1000, '2020-04-27 14:37:59', '2020-04-27 14:37:59'),
(223, 'G90', 'Chuột máy tính Fuhlen G90', 20, NULL, 'Tên sản phẩm: Chuột máy tính Fuhlen G90 Gaming USB LED RGB (Đen)', 'Tên sản phẩm: Chuột máy tính Fuhlen G90 Gaming USB LED RGB (Đen)\r\n\r\n- Fuhlen G90 công nghệ mới: nút bấm \'\'bất tử\'\'- Fuhlen G90 có thiết kế công thái học, có khuôn đặt ngón tay độc đáo.- có 7 nút bấm được thiết lập cho người dùng, điều chỉnh DPI trực tiếp.- 2000 DPI - tần số quét 125/250/500/1000 Hz.- LED xanh dương- Chiều dài dây 1,8m, đầu USB mạ vàng', 399000, 0, '162c.png', NULL, 0, 1000, '2020-04-27 14:42:43', '2020-04-27 14:42:43'),
(224, 'Dell', 'Chuột máy tính Dell', 20, NULL, 'Tên sản phẩm: Chuột máy tính Dell', 'Tên sản phẩm: Chuột máy tính Dell\r\n\r\n- Kiểu dáng thân thiện, phù hợp môi trường văn phòng\r\n- Thiết kế đơn giản\r\n- Chất liêu gia công cao\r\n- Kết nối USB', 105000, 0, '163c.png', NULL, 0, 1000, '2020-04-27 14:47:20', '2020-04-27 14:47:20'),
(225, 'G10+', 'Chuột máy tính có dây Newmen G10+', 20, NULL, 'Tên sản phẩm: Chuột máy tính có dây Newmen G10+ (Vàng)', 'Tên sản phẩm: Chuột máy tính có dây Newmen G10+ (Vàng)\r\n\r\n- Chuột máy tính Newmen G10+ \r\n- Chuẩn kết nối: USB \r\n- Cảm biến quang học, tốc độ 1600 DPI \r\n- Nút bấm Kailh bền bỉ', 179000, 0, '164c.png', NULL, 1, 1000, '2020-04-27 14:49:11', '2020-04-27 14:49:11'),
(226, 'GX1-Plus', 'Tên sản phẩm: Chuột máy tính Newmen Gaming GX1-Plus đen', 20, NULL, 'Tên sản phẩm: Chuột máy tính Newmen Gaming GX1-Plus đen', 'Tên sản phẩm: Chuột máy tính Newmen Gaming GX1-Plus đen\r\n\r\n- Độ phân giải 500-1000-1500-2000-4000DPI tuỳ chỉnh. - Đầu USB mạ vàng. - Được trang bị Pad Teflon & bi trọng lực để con chuột định vị trính xác hơn. - Hai bên uốn cong kê ngón cái và ngón út giúp bạn rất thoải mái khi sử dụng. - Các vân chống trơn trượt cùng hiệu ứng ánh sáng giúp bạn tăng độ kích thích khi sử dụng. - Dễ dàng điều khiển trong đêm đen nhờ LED xanh dương soi', 289000, 0, '165c.png', NULL, 0, 1000, '2020-04-27 14:51:41', '2020-04-27 14:51:41'),
(227, 'G10+', 'Chuột máy tính có dây Newmen G10+', 20, NULL, 'Tên sản phẩm: Chuột máy tính có dây Newmen G10+ (Đen)', 'Tên sản phẩm: Chuột máy tính có dây Newmen G10+ (Đen)\r\n\r\n- Chuột máy tính Newmen G10+ \r\n- Chuẩn kết nối: USB \r\n- Cảm biến quang học, tốc độ 1600 DPI \r\n- Nút bấm kailh switch bền bỉ', 179000, 0, '166c.png', NULL, 0, 1000, '2020-04-27 14:53:25', '2020-04-27 14:53:25'),
(228, 'EM908', 'Chuột máy tính Dareu EM908', 20, NULL, 'Tên sản phẩm: Chuột máy tính Dareu EM908', 'Tên sản phẩm: Chuột máy tính Dareu EM908\r\n\r\n- Chuột Dareu EM908 được thiết kế công thái học với một ngoại hình vừa vặn bàn tay,tạo cảm giác không nhức mỏi, thoải mái khi sử dụng một thời gian dài\r\n- Ngoài ra với dải đèn LED tinh tế RGB cùng 16.7 triệu màu quanh viền chuột\r\n- Với mắt cảm ứng BRAVO sensor nổi trội ( 6000 DPI với 6 nút tinh chỉnh ) cùng với gia tốc 150 IPS\r\n- Với Driver dễ sử dụng cùng với một loạt chương trình có thể điều chỉnh được. Từ màu sắc hiển thị cho tới các hiệu ứng, tốc độ chuột, thiết lập Tất cả đều dễ dàng sử dụng chỉ với 1 cú click chuột.', 399000, 0, '167c.png', NULL, 0, 1000, '2020-04-27 14:55:30', '2020-04-27 14:55:30'),
