(236, 'SOUNDSTICKS', 'Loa Harman/Kardon SOUNDSTICKS BT', 21, NULL, 'Tên sản phẩm: Loa Harman/Kardon SOUNDSTICKS BT', 'Tên sản phẩm: Loa Harman/Kardon SOUNDSTICKS BT\r\n\r\n- Loa Sound Sticks là loa vi tính siêu sang trọng với thiết kế trong suốt độc đáo - Sản phẩm được nâng cấp kết nối Bluetooth cho phép kết nối đến smartphone, tablet hay laptop tiện lợi - Dải tần số rộng 44 đến 20k Hz giúp cho loa có thể chơi được nhiều thể loại nhạc - Loa subwoofer cho tiếng bass sâu và trầm ấm - Hai loa vệ tinh mỗi bên với 4 loa dàn trải cho âm thanh chi tiết, âm hình rộng', 6000000, 0, '177l.png', NULL, 0, 1000, '2020-04-27 15:15:48', '2020-04-27 15:15:48'),
(237, 'ZH12S', 'Tai nghe Over-ear Zidli ZH12S (ShortMic)', 22, NULL, 'Tên sản phẩm: Tai nghe Over-ear Zidli ZH12S (ShortMic)', 'Tên sản phẩm: Tai nghe Over-ear Zidli ZH12S (ShortMic)\r\n\r\n- Tai nghe trùm tai (over-ear) với củ tai thiết kế thể thao và hiện đại. \r\n- Âm thanh giả lập 7.1 .\r\n- Kết nối: USB tích hợp card âm thanh trên headphone\r\n- Hiệu ứng ánh sáng led RGB thay đổi linh hoạt.\r\n- Đệm tai bằng da mềm chất lượng cao.\r\n- Bass chắc và sâu, mang lại hiệu ứng âm thanh.\r\n- Headband tự điều chỉnh kích thước phù hợp với người dùng\r\n- Thích hợp dùng cho cá nhân và các phòng máy trải nghiệm, kinh doanh.', 450000, 0, '180t.png', NULL, 0, 1000, '2020-04-27 15:19:37', '2020-04-27 15:19:37'),
(238, 'ZH6', 'Tai nghe Zidli ZH6 (3.5)', 22, NULL, 'Tên sản phẩm: Tai nghe Zidli ZH6 (3.5)', 'Tên sản phẩm: Tai nghe Zidli ZH6 (3.5)\r\n\r\n- Tai nghe trùm tai (over-ear) với thiết kế thể thao và hiện đại.\r\n- Âm thanh giả lập 7.1\r\n- Kết nối: USB/jack 3.5mm tích hợp card âm thanh trên headphone\r\n- Hiệu ứng ánh sáng led 7 màu.\r\n- Bass chắc và sâu, mang lại hiệu ứng âm thanh.\r\n- Headband tự điều chỉnh kích thước phù hợp với người dùng', 245000, 0, '181t.png', NULL, 0, 1000, '2020-04-27 15:21:43', '2020-04-27 15:21:43'),
(239, 'ZH12S', 'Tai nghe Zidli ZH12S PUBG LED', 22, NULL, 'Tên sản phẩm: Tai nghe Zidli ZH12S PUBG LED', 'Tên sản phẩm: Tai nghe Zidli ZH12S PUBG LED\r\n\r\n- Tai nghe trùm tai (over-ear) với củ tai thiết kế thể thao và hiện đại.  \r\n- Hỗ trợ âm thanh giả lập 7.1  \r\n- Kết nối: USB tích hợp card âm thanh trên headphone \r\n- Hiệu ứng PUBG led đặc biệt, độc đáo - Đệm tai bằng da mềm chất lượng cao.', 490000, 0, '182t.png', NULL, 0, 1000, '2020-04-27 15:23:43', '2020-04-27 15:23:43'),
(240, 'EH416', 'Tai nghe DAREU EH416 (Đen)', 22, NULL, 'Tên sản phẩm: Tai nghe DAREU EH416 (Đen)', 'Tên sản phẩm: Tai nghe DAREU EH416 (Đen)\r\n\r\n- Thương Hiệu: DAREU\r\n- Chuẩn kết nối : USB\r\n- Hiệu ứng giả lập âm thanh 7.1\r\n- Led tích hợp nổi bật', 499000, 0, '183t.png', NULL, 0, 1000, '2020-04-27 15:25:50', '2020-04-27 15:25:50'),
(241, 'EH722S', 'Tai nghe DARE-U EH722S (Đen)', 22, NULL, 'Tên sản phẩm: Tai nghe DARE-U EH722S (Đen)', 'Tên sản phẩm: Tai nghe DARE-U EH722S (Đen)\r\n\r\n- Hiệu ứng âm thanh giả lập 7.1 ấn tượng, trong trẻo. - Headband và đệm tai bằng da mềm giúp sử dụng lâu mà vẫn thoải mái. - Khung bằng hợp kim cao cấp, sang trọng. - Dây nhựa dài 2m, đầu kết nối USB mạ vàng. - Điều khiển volume ngay trên phone rất tiện lợi. - Micro rõ, lọc tạp âm rất tốt.', 699000, 0, '184t.png', NULL, 0, 1000, '2020-04-27 15:27:50', '2020-04-27 15:27:50'),
(242, 'ZH11S', 'Tai Nghe Zidli ZH11S', 22, NULL, 'Tên sản phẩm: Tai Nghe Zidli ZH11S', 'Tên sản phẩm: Tai Nghe Zidli ZH11S\r\n\r\n- Âm thanh vòm giả lập 7.1 cho không gian âm thanh rộng và sống động. - Led RGB 16,8 triệu màu. - Chuẩn giao tiếp : USB. - Độ bền cao, phù hợp với gamenet và môi trường thi đấu.', 650000, 0, '185t.png', NULL, 0, 1000, '2020-04-27 15:30:19', '2020-04-27 15:30:19'),
(243, 'ZH7', 'Tai nghe Zidli ZH7 (Đen)', 22, NULL, 'Tên sản phẩm: Tai nghe Zidli ZH7 (Đen)', 'Tên sản phẩm: Tai nghe Zidli ZH7 (Đen)\r\n\r\n- Tai nghe trùm tai (over-ear) với củ tai thiết kế thể thao và hiện đại.- Âm thanh giả lập 7.1- Kết nối: USB tích hợp card âm thanh trên headphone- Hiệu ứng ánh sáng led 7 màu.- Đệm tai bằng da mềm chất lượng cao.- Bass chắc và sâu, mang lại hiệu ứng âm thanh.- Headband tự điều chỉnh kích thước phù hợp với người dùng- Thích hợp dùng cho cá nhân và các phòng máy trải nghiệm, kinh doanh.', 449000, 0, '186t.png', NULL, 0, 1000, '2020-04-27 15:32:05', '2020-04-27 15:32:05'),
(244, 'GT-03', 'Tai nghe Tako GT-03 (Xanh)', 22, NULL, 'Tên sản phẩm: Tai nghe Tako GT-03 (Xanh)', 'Tên sản phẩm: Tai nghe Tako GT-03 (Xanh)\r\n\r\n- Thiết kế : Over Ear ( trùm kín quanh tai)\r\n- Dải tần: 20 - 20.000Hz\r\n- Độ nhạy loa: 115dB±3dB\r\n- Dải tần mic: 16 - 20.000Hz\r\n- Trở kháng mic: 2.200 Ohms\r\n- Jack: 3.5mm\r\n- Chiều dài dây: 2.0m', 105000, 0, '187t.png', NULL, 0, 1000, '2020-04-27 15:49:56', '2020-04-27 15:49:56'),
(245, 'R400', 'Thiết bị trình chiếu Logitech R400', 27, NULL, 'Tên sản phẩm: Thiết bị trình chiếu Logitech R400', 'Tên sản phẩm: Thiết bị trình chiếu Logitech R400\r\n\r\n- Bút trình chiếu Laser điều hướng slide cơ bản - Dễ dàng sử dụng, kết nối đơn giản chỉ với đầu thu USB - Công nghệ không dây 2.4 GHz cho phép di chuyển tự do và thoải mái với phạm vi hoạt động lên đến 15m - Con trỏ laze màu đỏ giúp dễ quan sát chính xác những gì đang trỏ đến', 749000, 0, '200c.png', NULL, 0, 1000, '2020-04-27 15:52:20', '2020-04-27 16:53:27'),
